  const [formDescription, setFormDescription] = useState('');
  const [formAmount, setFormAmount] = useState<number | string>('');
  const [formType, setFormType] = useState<TransactionType>('EXPENSE');
  const [formCategoryId, setFormCategoryId] = useState('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);

  // Category Form State
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [newCatName, setNewCatName] = useState('');
  const [newCatType, setNewCatType] = useState<TransactionType>('EXPENSE');
  const [newCatIcon, setNewCatIcon] = useState('📁');

  // Quick Category Mini-Form State
  const [quickCatName, setQuickCatName] = useState('');
  const [quickCatIcon, setQuickCatIcon] = useState('✨');

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) return;

    if (editingTransaction) {
      setTransactions(transactions.map(t => 
        t.id === editingTransaction.id 
        ? { ...t, description: formDescription, amount: Number(formAmount), type: formType, categoryId: formCategoryId, date: formDate } 
        : t
      ));
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        amount: Number(formAmount),
        description: formDescription,
        date: formDate,
        type: formType,
        categoryId: formCategoryId,
        tenantId: 't1'
      };
      setTransactions([newTransaction, ...transactions]);
    }
    closeTransactionModal();
  };

  const startEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setFormDescription(t.description);
    setFormAmount(t.amount);
    setFormType(t.type);
    setFormCategoryId(t.categoryId);
    setFormDate(t.date);
    setShowTransactionModal(true);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Tem certeza que deseja excluir esta transação?')) {
      setTransactions(transactions.filter(t => t.id !== id));
    }
  };

  const closeTransactionModal = () => {
    setShowTransactionModal(false);
    setShowQuickCategoryForm(false);
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormType('EXPENSE');
    setFormCategoryId(categories[0]?.id || '');
    setFormDate(new Date().toISOString().split('T')[0]);
  };

  const handleSaveCategory = () => {
    if (!newCatName.trim()) return;

    if (editingCategory) {
      setCategories(categories.map(c => c.id === editingCategory.id ? { ...c, name: newCatName, type: newCatType, icon: newCatIcon } : c));
    } else {
      const newCat: Category = {
        id: Math.random().toString(36).substr(2, 9),
        name: newCatName,
        type: newCatType,
        icon: newCatIcon,
        color: newCatType === 'INCOME' ? 'bg-green-500' : 'bg-red-500'
      };
      setCategories([...categories, newCat]);
    }
    resetCategoryForm();
  };

  const handleQuickSaveCategory = () => {
    if (!quickCatName.trim()) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newCat: Category = {
      id: newId,
      name: quickCatName,
      type: formType, // Match the current transaction type
      icon: quickCatIcon,
      color: formType === 'INCOME' ? 'bg-green-500' : 'bg-red-500'
    };

    setCategories([...categories, newCat]);
    setFormCategoryId(newId); // Select the newly created category
    setQuickCatName('');
    setQuickCatIcon('✨');
    setShowQuickCategoryForm(false);
  };

  const resetCategoryForm = () => {
    setEditingCategory(null);
    setNewCatName('');
    setNewCatType('EXPENSE');
    setNewCatIcon('📁');
  };

  const deleteCategory = (id: string) => {
    if (confirm('Tem certeza que deseja excluir esta categoria? Transações vinculadas ficarão sem categoria.')) {
      setCategories(categories.filter(c => c.id !== id));
    }
  };

  const startEditCategory = (cat: Category) => {
    setEditingCategory(cat);
    setNewCatName(cat.name);
    setNewCatType(cat.type);
    setNewCatIcon(cat.icon);
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="relative flex-1 max-w-md w-full">
          <svg className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
          <input 
            type="text" 
            placeholder="Pesquisar descrição, categoria ou valor..."
            className="w-full pl-10 pr-4 py-2.5 bg-white border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 shadow-sm transition-all"
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <button 
            onClick={() => setShowCategoryModal(true)}
            className="flex-1 sm:flex-none border border-gray-200 bg-white hover:bg-gray-50 text-gray-700 px-4 py-2.5 rounded-xl font-semibold flex items-center justify-center gap-2 transition-all shadow-sm"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
            Categorias
          </button>
          <button 
            onClick={() => {
              setFormCategoryId(categories[0]?.id || '');
              setShowTransactionModal(true);
            }}
            className="flex-1 sm:flex-none bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-md active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
            Nova Transação
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-gray-50 border-b border-gray-100">
            <tr>
              <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Data</th>
              <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Descrição</th>
              <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Categoria</th>
              <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider text-right">Valor</th>
              <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {transactions.map((t) => {
              const category = categories.find(c => c.id === t.categoryId);
              return (
                <tr key={t.id} className="hover:bg-gray-50/50 transition-colors">
                  <td className="px-6 py-4 text-sm text-gray-600">{t.date}</td>
                  <td className="px-6 py-4">
                    <p className="text-sm font-semibold text-gray-800">{t.description}</p>
                    <p className="text-xs text-gray-400">ID: {t.id}</p>
                  </td>
                  <td className="px-6 py-4">
                    <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
                      <span>{category?.icon || '📁'}</span>
                      {category?.name || 'Sem Categoria'}
                    </span>
                  </td>
                  <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'INCOME' ? 'text-green-600' : 'text-red-600'}`}>
                    {t.type === 'INCOME' ? '+' : '-'} {t.amount.toLocaleString('pt-MZ')} MZN
                  </td>
                  <td className="px-6 py-4 text-center">
                    <button 
                      onClick={() => startEditTransaction(t)}
                      className="p-1.5 text-gray-400 hover:text-blue-600 transition-colors"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                    </button>
                    <button 
                      onClick={() => deleteTransaction(t.id)}
                      className="p-1.5 text-gray-400 hover:text-red-600 transition-colors ml-2"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/><line x1="10" x2="10" y1="11" y2="17"/><line x1="14" x2="14" y1="11" y2="17"/></svg>
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {transactions.length === 0 && (
          <div className="p-12 text-center">
            <p className="text-gray-400">Nenhuma transação cadastrada.</p>
          </div>
        )}
      </div>

      {/* Transaction Modal */}
      {showTransactionModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl animate-scaleIn overflow-hidden">
            <div className="px-6 py-4 border-b flex items-center justify-between bg-gray-50">
              <h3 className="text-lg font-bold text-gray-800">
                {editingTransaction ? 'Editar Transação' : 'Nova Transação'}
              </h3>
              <button onClick={closeTransactionModal} className="text-gray-400 hover:text-gray-600 transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              </button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Descrição</label>
                <input 
                  type="text" 
                  value={formDescription}
                  onChange={(e) => setFormDescription(e.target.value)}
                  className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all" 
                  placeholder="Ex: Pagamento Fornecedor X" 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Valor (MZN)</label>
                  <input 
                    type="number" 
                    value={formAmount}
                    onChange={(e) => setFormAmount(e.target.value)}
                    className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all" 
                    placeholder="0.00" 
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Tipo</label>
                  <select 
                    value={formType}
                    onChange={(e) => setFormType(e.target.value as TransactionType)}
                    className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  >
                    <option value="EXPENSE">Despesa</option>
                    <option value="INCOME">Receita</option>
                  </select>
                </div>
              </div>

              {/* Category Selection Area with Quick Add */}
              <div className="space-y-2 border-t pt-4">
                <div className="flex justify-between items-center">
                  <label className="block text-sm font-medium text-gray-700">Categoria</label>
                  {!showQuickCategoryForm && (
                    <button 
                      onClick={() => setShowQuickCategoryForm(true)}
                      className="text-xs font-bold text-blue-600 hover:text-blue-700 flex items-center gap-1 transition-colors"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
                      Nova Categoria
                    </button>
                  )}
                </div>

                {showQuickCategoryForm ? (
                  <div className="bg-blue-50 p-3 rounded-xl border border-blue-100 space-y-3 animate-slideDown">
                    <div className="flex gap-2">
                      <input 
                        type="text" 
                        value={quickCatIcon}
                        onChange={(e) => setQuickCatIcon(e.target.value)}
                        className="w-12 p-2 bg-white border border-blue-200 rounded-lg text-center text-xl outline-none focus:ring-2 focus:ring-blue-400"
                        placeholder="✨"
                      />
                      <input 
                        type="text" 
                        value={quickCatName}
                        onChange={(e) => setQuickCatName(e.target.value)}
                        className="flex-1 p-2 bg-white border border-blue-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-400"
                        placeholder="Nome da categoria..."
                        autoFocus
                      />
                    </div>
                    <div className="flex gap-2">
                      <button 
                        onClick={handleQuickSaveCategory}
                        className="flex-1 py-1.5 bg-blue-600 text-white text-xs font-bold rounded-lg hover:bg-blue-700 transition-colors"
                      >
                        Confirmar
                      </button>
                      <button 
                        onClick={() => setShowQuickCategoryForm(false)}
                        className="flex-1 py-1.5 bg-white text-gray-500 text-xs font-bold rounded-lg border border-gray-200 hover:bg-gray-50 transition-colors"
                      >
                        Cancelar
                      </button>
                    </div>
                  </div>
                ) : (
                  <select 
                    value={formCategoryId}
                    onChange={(e) => setFormCategoryId(e.target.value)}
                    className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  >
                    {categories
                      .filter(cat => cat.type === formType) // Filter categories by current transaction type
                      .map(cat => (
                        <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>
                      ))
                    }
                    {/* Fallback for cases where no category matches the type */}
                    {categories.filter(cat => cat.type === formType).length === 0 && (
                      <option disabled value="">Nenhuma categoria de {formType === 'INCOME' ? 'receita' : 'despesa'}</option>
                    )}
                  </select>
                )}
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Data</label>
                <input 
                  type="date" 
                  value={formDate}
                  onChange={(e) => setFormDate(e.target.value)}
                  className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                />
              </div>

              {!showQuickCategoryForm && (
                <button 
                  onClick={handleSaveTransaction}
                  className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold transition-all shadow-lg mt-4 active:scale-95"
                >
                  {editingTransaction ? 'Salvar Alterações' : 'Salvar Transação'}
                </button>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Categories Management Modal */}
      {showCategoryModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-2xl shadow-2xl animate-scaleIn overflow-hidden flex flex-col max-h-[90vh]">
            <div className="px-6 py-4 border-b flex items-center justify-between bg-gray-50">
              <h3 className="text-lg font-bold text-gray-800">Gerir Categorias</h3>
              <button onClick={() => { setShowCategoryModal(false); resetCategoryForm(); }} className="text-gray-400 hover:text-gray-600">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              </button>
            </div>

            <div className="p-6 overflow-y-auto flex-1 grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* Left Column: Form */}
              <div className="space-y-4">
                <h4 className="font-bold text-gray-700 border-b pb-2">
                  {editingCategory ? 'Editar Categoria' : 'Adicionar Nova'}
                </h4>
                <div>
                  <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Nome da Categoria</label>
                  <input 
                    type="text" 
                    value={newCatName}
                    onChange={(e) => setNewCatName(e.target.value)}
                    className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" 
                    placeholder="Ex: Lazer" 
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Ícone</label>
                    <input 
                      type="text" 
                      value={newCatIcon}
                      onChange={(e) => setNewCatIcon(e.target.value)}
                      className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 text-center text-xl" 
                      placeholder="📁" 
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Tipo</label>
                    <select 
                      value={newCatType}
                      onChange={(e) => setNewCatType(e.target.value as TransactionType)}
                      className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      <option value="EXPENSE">Despesa</option>
                      <option value="INCOME">Receita</option>
                    </select>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={handleSaveCategory}
                    className="flex-1 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold transition-all"
                  >
                    {editingCategory ? 'Atualizar' : 'Criar Categoria'}
                  </button>
                  {editingCategory && (
                    <button 
                      onClick={resetCategoryForm}
                      className="px-4 py-2.5 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-lg font-bold transition-all"
                    >
                      Cancelar
                    </button>
                  )}
                </div>
              </div>

              {/* Right Column: List */}
              <div className="space-y-4">
                <h4 className="font-bold text-gray-700 border-b pb-2">Lista de Categorias</h4>
                <div className="space-y-2 max-h-[400px] overflow-y-auto pr-2">
                  {categories.map((cat) => (
                    <div key={cat.id} className="flex items-center justify-between p-3 bg-gray-50 border border-gray-100 rounded-xl group hover:border-blue-200 transition-all">
                      <div className="flex items-center gap-3">
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-lg ${cat.type === 'INCOME' ? 'bg-green-100' : 'bg-red-100'}`}>
                          {cat.icon}
                        </div>
                        <div>
                          <p className="text-sm font-bold text-gray-800">{cat.name}</p>
                          <p className={`text-[10px] font-bold uppercase ${cat.type === 'INCOME' ? 'text-green-600' : 'text-red-600'}`}>
                            {cat.type === 'INCOME' ? 'Receita' : 'Despesa'}
                          </p>
                        </div>
                      </div>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => startEditCategory(cat)}
                          className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"
                        >
                          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                        </button>
                        <button 
                          onClick={() => deleteCategory(cat.id)}
                          className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg"
                        >
                          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/><line x1="10" x2="10" y1="11" y2="17"/><line x1="14" x2="14" y1="11" y2="17"/></svg>
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="px-6 py-4 bg-gray-50 border-t flex justify-end">
              <button 
                onClick={() => { setShowCategoryModal(false); resetCategoryForm(); }}
                className="px-6 py-2 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 transition-all"
              >
                Concluir
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export type UserRole = 'ADMIN' | 'EMPLOYEE' | 'OWNER';
export type AccountType = 'PERSONAL' | 'BUSINESS';
export type TransactionType = 'INCOME' | 'EXPENSE';
export type TransactionStatus = 'PENDING' | 'COMPLETED' | 'OVERDUE';

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  tenantId: string;
}

export interface Tenant {
  id: string;
  name: string;
  type: AccountType;
  plan: 'FREE' | 'PRO' | 'ENTERPRISE';
}

export interface Category {
  id: string;
  name: string;
  icon: string;
  color: string;
  type: TransactionType;
}

export interface Transaction {
  id: string;
  amount: number;
  description: string;
  date: string;
  type: TransactionType;
  status: TransactionStatus;
  categoryId: string;
  tenantId: string;
}

export interface Entity {
  id: string;
  name: string;
  type: 'CLIENT' | 'SUPPLIER';
  email?: string;
}

import React, { useState } from 'react';
import { AccountType, Transaction, Category, TransactionType, TransactionStatus } from '../types';

export const TransactionsPage: React.FC<{ mode: AccountType }> = ({ mode }) => {
  const [showTransactionModal, setShowTransactionModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [showQuickCategoryForm, setShowQuickCategoryForm] = useState(false);

  // State for Transactions
  const [transactions, setTransactions] = useState<Transaction[]>([
    { id: '1', amount: 4500, description: 'Venda de Produto A', date: '2024-05-20', type: 'INCOME', status: 'COMPLETED', categoryId: '2', tenantId: 't1' },
    { id: '2', amount: 1200, description: 'Fornecedor de Embalagens', date: '2024-05-19', type: 'EXPENSE', status: 'PENDING', categoryId: '4', tenantId: 't1' },
    { id: '3', amount: 35000, description: 'Aluguel Escritório', date: '2024-05-15', type: 'EXPENSE', status: 'COMPLETED', categoryId: '3', tenantId: 't1' },
    { id: '4', amount: 15000, description: 'Consultoria Mensal', date: '2024-05-10', type: 'INCOME', status: 'OVERDUE', categoryId: '2', tenantId: 't1' },
  ]);

  // State for Categories
  const [categories, setCategories] = useState<Category[]>([
    { id: '1', name: 'Salário', icon: '💰', color: 'bg-green-500', type: 'INCOME' },
    { id: '2', name: 'Vendas', icon: '🛒', color: 'bg-blue-500', type: 'INCOME' },
    { id: '3', name: 'Aluguel', icon: '🏠', color: 'bg-red-500', type: 'EXPENSE' },
    { id: '4', name: 'Alimentação', icon: '🍔', color: 'bg-orange-500', type: 'EXPENSE' },
    { id: '5', name: 'Transporte', icon: '🚗', color: 'bg-purple-500', type: 'EXPENSE' },
  ]);

  // Transaction Form State
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formDescription, setFormDescription] = useState('');
  const [formAmount, setFormAmount] = useState<number | string>('');
  const [formType, setFormType] = useState<TransactionType>('EXPENSE');
  const [formStatus, setFormStatus] = useState<TransactionStatus>('COMPLETED');
  const [formCategoryId, setFormCategoryId] = useState('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);

  // Category Form State
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [newCatName, setNewCatName] = useState('');
  const [newCatType, setNewCatType] = useState<TransactionType>('EXPENSE');
  const [newCatIcon, setNewCatIcon] = useState('📁');

  // Quick Category Mini-Form State
  const [quickCatName, setQuickCatName] = useState('');
  const [quickCatIcon, setQuickCatIcon] = useState('✨');

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) return;

    if (editingTransaction) {
      setTransactions(transactions.map(t => 
        t.id === editingTransaction.id 
        ? { ...t, description: formDescription, amount: Number(formAmount), type: formType, status: formStatus, categoryId: formCategoryId, date: formDate } 
        : t
      ));
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        amount: Number(formAmount),
        description: formDescription,
        date: formDate,
        type: formType,
        status: formStatus,
        categoryId: formCategoryId,
        tenantId: 't1'
      };
      setTransactions([newTransaction, ...transactions]);
    }
    closeTransactionModal();
  };

  const startEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setFormDescription(t.description);
    setFormAmount(t.amount);
    setFormType(t.type);
    setFormStatus(t.status);
    setFormCategoryId(t.categoryId);
    setFormDate(t.date);
    setShowTransactionModal(true);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Tem certeza que deseja excluir esta transação?')) {
      setTransactions(transactions.filter(t => t.id !== id));
    }
  };

  const closeTransactionModal = () => {
    setShowTransactionModal(false);
    setShowQuickCategoryForm(false);
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormType('EXPENSE');
    setFormStatus('COMPLETED');
    setFormCategoryId(categories[0]?.id || '');
    setFormDate(new Date().toISOString().split('T')[0]);
  };

  const handleSaveCategory = () => {
    if (!newCatName.trim()) return;

    if (editingCategory) {
      setCategories(categories.map(c => c.id === editingCategory.id ? { ...c, name: newCatName, type: newCatType, icon: newCatIcon } : c));
    } else {
      const newCat: Category = {
        id: Math.random().toString(36).substr(2, 9),
        name: newCatName,
        type: newCatType,
        icon: newCatIcon,
        color: newCatType === 'INCOME' ? 'bg-green-500' : 'bg-red-500'
      };
      setCategories([...categories, newCat]);
    }
    resetCategoryForm();
  };

  const handleQuickSaveCategory = () => {
    if (!quickCatName.trim()) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newCat: Category = {
      id: newId,
      name: quickCatName,
      type: formType, 
      icon: quickCatIcon,
      color: formType === 'INCOME' ? 'bg-green-500' : 'bg-red-500'
    };

    setCategories([...categories, newCat]);
    setFormCategoryId(newId); 
    setQuickCatName('');
    setQuickCatIcon('✨');
    setShowQuickCategoryForm(false);
  };

  const resetCategoryForm = () => {
    setEditingCategory(null);
    setNewCatName('');
    setNewCatType('EXPENSE');
    setNewCatIcon('📁');
  };

  const deleteCategory = (id: string) => {
    if (confirm('Tem certeza que deseja excluir esta categoria? Transações vinculadas ficarão sem categoria.')) {
      setCategories(categories.filter(c => c.id !== id));
    }
  };

  const startEditCategory = (cat: Category) => {
    setEditingCategory(cat);
    setNewCatName(cat.name);
    setNewCatType(cat.type);
    setNewCatIcon(cat.icon);
  };

  const getStatusBadge = (status: TransactionStatus) => {
    switch (status) {
      case 'COMPLETED':
        return <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-green-100 text-green-700">COMPLETO</span>;
      case 'PENDING':
        return <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-amber-100 text-amber-700">PENDENTE</span>;
      case 'OVERDUE':
        return <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-red-100 text-red-700">ATRASADO</span>;
      default:
        return null;
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="relative flex-1 max-w-md w-full">
          <svg className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
          <input 
            type="text" 
            placeholder="Pesquisar descrição, categoria ou valor..."
            className="w-full pl-10 pr-4 py-2.5 bg-white border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 shadow-sm transition-all"
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <button 
            onClick={() => setShowCategoryModal(true)}
            className="flex-1 sm:flex-none border border-gray-200 bg-white hover:bg-gray-50 text-gray-700 px-4 py-2.5 rounded-xl font-semibold flex items-center justify-center gap-2 transition-all shadow-sm"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
            Categorias
          </button>
          <button 
            onClick={() => {
              setFormCategoryId(categories[0]?.id || '');
              setShowTransactionModal(true);
            }}
            className="flex-1 sm:flex-none bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-md active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
            Nova Transação
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 border-b border-gray-100">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Data</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Descrição</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Categoria</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider text-right">Valor</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {transactions.map((t) => {
                const category = categories.find(c => c.id === t.categoryId);
                return (
                  <tr key={t.id} className="hover:bg-gray-50/50 transition-colors">
                    <td className="px-6 py-4 text-sm text-gray-600 whitespace-nowrap">{t.date}</td>
                    <td className="px-6 py-4">
                      <p className="text-sm font-semibold text-gray-800">{t.description}</p>
                      <p className="text-xs text-gray-400">ID: {t.id}</p>
                    </td>
                    <td className="px-6 py-4">
                      <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
                        <span>{category?.icon || '📁'}</span>
                        {category?.name || 'Sem Categoria'}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      {getStatusBadge(t.status)}
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right whitespace-nowrap ${t.type === 'INCOME' ? 'text-green-600' : 'text-red-600'}`}>
                      {t.type === 'INCOME' ? '+' : '-'} {t.amount.toLocaleString('pt-MZ')} MZN
                    </td>
                    <td className="px-6 py-4 text-center whitespace-nowrap">
                      <button 
                        onClick={() => startEditTransaction(t)}
                        className="p-1.5 text-gray-400 hover:text-blue-600 transition-colors"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                      </button>
                      <button 
                        onClick={() => deleteTransaction(t.id)}
                        className="p-1.5 text-gray-400 hover:text-red-600 transition-colors ml-2"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/><line x1="10" x2="10" y1="11" y2="17"/><line x1="14" x2="14" y1="11" y2="17"/></svg>
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        {transactions.length === 0 && (
          <div className="p-12 text-center">
            <p className="text-gray-400">Nenhuma transação cadastrada.</p>
          </div>
        )}
      </div>

      {/* Transaction Modal */}
      {showTransactionModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl animate-scaleIn overflow-hidden">
            <div className="px-6 py-4 border-b flex items-center justify-between bg-gray-50">
              <h3 className="text-lg font-bold text-gray-800">
                {editingTransaction ? 'Editar Transação' : 'Nova Transação'}
              </h3>
              <button onClick={closeTransactionModal} className="text-gray-400 hover:text-gray-600 transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              </button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Descrição</label>
                <input 
                  type="text" 
                  value={formDescription}
                  onChange={(e) => setFormDescription(e.target.value)}
                  className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all" 
                  placeholder="Ex: Pagamento Fornecedor X" 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Valor (MZN)</label>
                  <input 
                    type="number" 
                    value={formAmount}
                    onChange={(e) => setFormAmount(e.target.value)}
                    className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all" 
                    placeholder="0.00" 
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Tipo</label>
                  <select 
                    value={formType}
                    onChange={(e) => setFormType(e.target.value as TransactionType)}
                    className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  >
                    <option value="EXPENSE">Despesa</option>
                    <option value="INCOME">Receita</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
                  <select 
                    value={formStatus}
                    onChange={(e) => setFormStatus(e.target.value as TransactionStatus)}
                    className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  >
                    <option value="COMPLETED">Completo</option>
                    <option value="PENDING">Pendente</option>
                    <option value="OVERDUE">Atrasado</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Data</label>
                  <input 
                    type="date" 
                    value={formDate}
                    onChange={(e) => setFormDate(e.target.value)}
                    className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  />
                </div>
              </div>

              {/* Category Selection Area with Quick Add */}
              <div className="space-y-2 border-t pt-4">
                <div className="flex justify-between items-center">
                  <label className="block text-sm font-medium text-gray-700">Categoria</label>
                  {!showQuickCategoryForm && (
                    <button 
                      onClick={() => setShowQuickCategoryForm(true)}
                      className="text-xs font-bold text-blue-600 hover:text-blue-700 flex items-center gap-1 transition-colors"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
                      Nova Categoria
                    </button>
                  )}
                </div>

                {showQuickCategoryForm ? (
                  <div className="bg-blue-50 p-3 rounded-xl border border-blue-100 space-y-3 animate-slideDown">
                    <div className="flex gap-2">
                      <input 
                        type="text" 
                        value={quickCatIcon}
                        onChange={(e) => setQuickCatIcon(e.target.value)}
                        className="w-12 p-2 bg-white border border-blue-200 rounded-lg text-center text-xl outline-none focus:ring-2 focus:ring-blue-400"
                        placeholder="✨"
                      />
                      <input 
                        type="text" 
                        value={quickCatName}
                        onChange={(e) => setQuickCatName(e.target.value)}
                        className="flex-1 p-2 bg-white border border-blue-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-400"
                        placeholder="Nome da categoria..."
                        autoFocus
                      />
                    </div>
                    <div className="flex gap-2">
                      <button 
                        onClick={handleQuickSaveCategory}
                        className="flex-1 py-1.5 bg-blue-600 text-white text-xs font-bold rounded-lg hover:bg-blue-700 transition-colors"
                      >
                        Confirmar
                      </button>
                      <button 
                        onClick={() => setShowQuickCategoryForm(false)}
                        className="flex-1 py-1.5 bg-white text-gray-500 text-xs font-bold rounded-lg border border-gray-200 hover:bg-gray-50 transition-colors"
                      >
                        Cancelar
                      </button>
                    </div>
                  </div>
                ) : (
                  <select 
                    value={formCategoryId}
                    onChange={(e) => setFormCategoryId(e.target.value)}
                    className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  >
                    {categories
                      .filter(cat => cat.type === formType) 
                      .map(cat => (
                        <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>
                      ))
                    }
                    {categories.filter(cat => cat.type === formType).length === 0 && (
                      <option disabled value="">Nenhuma categoria de {formType === 'INCOME' ? 'receita' : 'despesa'}</option>
                    )}
                  </select>
                )}
              </div>

              {!showQuickCategoryForm && (
                <button 
                  onClick={handleSaveTransaction}
                  className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold transition-all shadow-lg mt-4 active:scale-95"
                >
                  {editingTransaction ? 'Salvar Alterações' : 'Salvar Transação'}
                </button>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Categories Management Modal */}
      {showCategoryModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-2xl shadow-2xl animate-scaleIn overflow-hidden flex flex-col max-h-[90vh]">
            <div className="px-6 py-4 border-b flex items-center justify-between bg-gray-50">
              <h3 className="text-lg font-bold text-gray-800">Gerir Categorias</h3>
              <button onClick={() => { setShowCategoryModal(false); resetCategoryForm(); }} className="text-gray-400 hover:text-gray-600">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              </button>
            </div>

            <div className="p-6 overflow-y-auto flex-1 grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* Left Column: Form */}
              <div className="space-y-4">
                <h4 className="font-bold text-gray-700 border-b pb-2">
                  {editingCategory ? 'Editar Categoria' : 'Adicionar Nova'}
                </h4>
                <div>
                  <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Nome da Categoria</label>
                  <input 
                    type="text" 
                    value={newCatName}
                    onChange={(e) => setNewCatName(e.target.value)}
                    className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" 
                    placeholder="Ex: Lazer" 
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Ícone</label>
                    <input 
                      type="text" 
                      value={newCatIcon}
                      onChange={(e) => setNewCatIcon(e.target.value)}
                      className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 text-center text-xl" 
                      placeholder="📁" 
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Tipo</label>
                    <select 
                      value={newCatType}
                      onChange={(e) => setNewCatType(e.target.value as TransactionType)}
                      className="w-full p-2.5 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      <option value="EXPENSE">Despesa</option>
                      <option value="INCOME">Receita</option>
                    </select>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={handleSaveCategory}
                    className="flex-1 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold transition-all"
                  >
                    {editingCategory ? 'Atualizar' : 'Criar Categoria'}
                  </button>
                  {editingCategory && (
                    <button 
                      onClick={resetCategoryForm}
                      className="px-4 py-2.5 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-lg font-bold transition-all"
                    >
                      Cancelar
                    </button>
                  )}
                </div>
              </div>

              {/* Right Column: List */}
              <div className="space-y-4">
                <h4 className="font-bold text-gray-700 border-b pb-2">Lista de Categorias</h4>
                <div className="space-y-2 max-h-[400px] overflow-y-auto pr-2">
                  {categories.map((cat) => (
                    <div key={cat.id} className="flex items-center justify-between p-3 bg-gray-50 border border-gray-100 rounded-xl group hover:border-blue-200 transition-all">
                      <div className="flex items-center gap-3">
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-lg ${cat.type === 'INCOME' ? 'bg-green-100' : 'bg-red-100'}`}>
                          {cat.icon}
                        </div>
                        <div>
                          <p className="text-sm font-bold text-gray-800">{cat.name}</p>
                          <p className={`text-[10px] font-bold uppercase ${cat.type === 'INCOME' ? 'text-green-600' : 'text-red-600'}`}>
                            {cat.type === 'INCOME' ? 'Receita' : 'Despesa'}
                          </p>
                        </div>
                      </div>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => startEditCategory(cat)}
                          className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"
                        >
                          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                        </button>
                        <button 
                          onClick={() => deleteCategory(cat.id)}
                          className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg"
                        >
                          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/><line x1="10" x2="10" y1="11" y2="17"/><line x1="14" x2="14" y1="11" y2="17"/></svg>
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="px-6 py-4 bg-gray-50 border-t flex justify-end">
              <button 
                onClick={() => { setShowCategoryModal(false); resetCategoryForm(); }}
                className="px-6 py-2 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 transition-all"
              >
                Concluir
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export type UserRole = 'ADMIN' | 'EMPLOYEE' | 'OWNER';
export type AccountType = 'PERSONAL' | 'BUSINESS';
export type TransactionType = 'INCOME' | 'EXPENSE';
export type TransactionStatus = 'PENDING' | 'COMPLETED' | 'OVERDUE';

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  tenantId: string;
  active: boolean;
}

export interface Tenant {
  id: string;
  name: string;
  type: AccountType;
  plan: 'FREE' | 'PRO' | 'ENTERPRISE';
}

export interface AuthResponse {
  user: User;
  tenant: Tenant;
  accessToken: string;
  refreshToken: string;
}

export interface Category {
  id: string;
  name: string;
  icon: string;
  color: string;
  type: TransactionType;
}

export interface Transaction {
  id: string;
  amount: number;
  description: string;
  date: string;
  type: TransactionType;
  status: TransactionStatus;
  categoryId: string;
  tenantId: string;
}

export interface Entity {
  id: string;
  name: string;
  type: 'CLIENT' | 'SUPPLIER';
  email?: string;
}

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { ArchitectureDoc } from './components/ArchitectureDoc';
import { TransactionsPage } from './components/TransactionsPage';
import { BusinessManager } from './components/BusinessManager';
import { LoginPage } from './components/LoginPage';
import { AccountType, User, Tenant } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'transactions' | 'business' | 'docs'>('dashboard');
  const [accountMode, setAccountMode] = useState<AccountType>('PERSONAL');

  // Auth State
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [user, setUser] = useState<User | null>(null);
  const [tenant, setTenant] = useState<Tenant | null>(null);

  const handleLoginSuccess = (data: { user: User; tenant: Tenant }) => {
    setUser(data.user);
    setTenant(data.tenant);
    setAccountMode(data.tenant.type);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setTenant(null);
  };

  if (!isAuthenticated) {
    return <LoginPage onLoginSuccess={handleLoginSuccess} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        accountMode={accountMode}
        setAccountMode={setAccountMode}
        onLogout={handleLogout}
      />

      <main className="flex-1 lg:ml-64 p-4 md:p-8">
        <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-gray-800">
              {activeTab === 'dashboard' && 'Dashboard Financeiro'}
              {activeTab === 'transactions' && 'Transações'}
              {activeTab === 'business' && 'Gestão de Negócio'}
              {activeTab === 'docs' && 'Documentação Técnica'}
            </h1>
            <p className="text-gray-500 text-sm">
              Visualização de conta: <span className="font-semibold text-blue-600">{tenant?.name}</span> ({accountMode === 'PERSONAL' ? 'Pessoa Física' : 'PME'})
            </p>
          </div>

          <div className="flex items-center gap-4">
            <button className="p-2 bg-white border rounded-full text-gray-400 hover:text-blue-600 shadow-sm transition-colors relative">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 8a6 6 0 0 1 12 0c0 7 3 9 3 9H3s3-2 3-9"/><path d="M10.3 21a1.94 1.94 0 0 0 3.4 0"/></svg>
              <span className="absolute top-0 right-0 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
            </button>
            <div className="flex items-center gap-3 pl-4 border-l">
              <div className="text-right hidden sm:block">
                <p className="text-sm font-semibold text-gray-800">{user?.name}</p>
                <p className="text-xs text-gray-400">{tenant?.plan} Plan</p>
              </div>
              <div className="w-10 h-10 rounded-full bg-blue-600 flex items-center justify-center text-white font-bold border-2 border-white shadow-sm">
                {user?.name.charAt(0)}
              </div>
            </div>
          </div>
        </header>

        <section className="max-w-7xl mx-auto">
          {activeTab === 'dashboard' && <Dashboard mode={accountMode} />}
          {activeTab === 'transactions' && <TransactionsPage mode={accountMode} />}
          {activeTab === 'business' && <BusinessManager />}
          {activeTab === 'docs' && <ArchitectureDoc />}
        </section>
      </main>
    </div>
  );
};

export default App;

