  const [formStatus, setFormStatus] = useState<TransactionStatus>('COMPLETED');
  const [formCategoryId, setFormCategoryId] = useState('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);

  // Category Form State
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [newCatName, setNewCatName] = useState('');
  const [newCatType, setNewCatType] = useState<TransactionType>('EXPENSE');
  const [newCatIcon, setNewCatIcon] = useState('📁');

  // Quick Category Mini-Form State
  const [quickCatName, setQuickCatName] = useState('');
  const [quickCatIcon, setQuickCatIcon] = useState('✨');

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) return;

    if (editingTransaction) {
      setTransactions(transactions.map(t => 
        t.id === editingTransaction.id 
        ? { ...t, description: formDescription, amount: Number(formAmount), type: formType, status: formStatus, categoryId: formCategoryId, date: formDate } 
        : t
      ));
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        amount: Number(formAmount),
        description: formDescription,
        date: formDate,
        type: formType,
        status: formStatus,
        categoryId: formCategoryId,
        tenantId: 't1'
      };
      setTransactions([newTransaction, ...transactions]);
    }
    closeTransactionModal();
  };

  const startEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setFormDescription(t.description);
    setFormAmount(t.amount);
    setFormType(t.type);
    setFormStatus(t.status);
    setFormCategoryId(t.categoryId);
    setFormDate(t.date);
    setShowTransactionModal(true);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Tem certeza que deseja excluir esta transação?')) {
      setTransactions(transactions.filter(t => t.id !== id));
    }
  };

  const closeTransactionModal = () => {
    setShowTransactionModal(false);
    setShowQuickCategoryForm(false);
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormType('EXPENSE');
    setFormStatus('COMPLETED');
    setFormCategoryId(categories[0]?.id || '');
    setFormDate(new Date().toISOString().split('T')[0]);
  };

  const handleSaveCategory = () => {
    if (!newCatName.trim()) return;

    if (editingCategory) {
      setCategories(categories.map(c => c.id === editingCategory.id ? { ...c, name: newCatName, type: newCatType, icon: newCatIcon } : c));
    } else {
      const newCat: Category = {
        id: Math.random().toString(36).substr(2, 9),
        name: newCatName,
        type: newCatType,
        icon: newCatIcon,
        color: newCatType === 'INCOME' ? 'bg-emerald-500' : 'bg-rose-500'
      };
      setCategories([...categories, newCat]);
    }
    resetCategoryForm();
  };

  const handleQuickSaveCategory = () => {
    if (!quickCatName.trim()) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newCat: Category = {
      id: newId,
      name: quickCatName,
      type: formType, 
      icon: quickCatIcon,
      color: formType === 'INCOME' ? 'bg-emerald-500' : 'bg-rose-500'
    };

    setCategories([...categories, newCat]);
    setFormCategoryId(newId); 
    setQuickCatName('');
    setQuickCatIcon('✨');
    setShowQuickCategoryForm(false);
  };

  const resetCategoryForm = () => {
    setEditingCategory(null);
    setNewCatName('');
    setNewCatType('EXPENSE');
    setNewCatIcon('📁');
  };

  const deleteCategory = (id: string) => {
    if (confirm('Tem certeza que deseja excluir esta categoria? Transações vinculadas ficarão sem categoria.')) {
      setCategories(categories.filter(c => c.id !== id));
    }
  };

  const startEditCategory = (cat: Category) => {
    setEditingCategory(cat);
    setNewCatName(cat.name);
    setNewCatType(cat.type);
    setNewCatIcon(cat.icon);
  };

