    switch (status) {
      case 'COMPLETED':
        return <span className="px-3 py-1 rounded-full text-[10px] font-black bg-emerald-50 text-emerald-600 border border-emerald-100 uppercase tracking-tight">Efetivado</span>;
      case 'PENDING':
        return <span className="px-3 py-1 rounded-full text-[10px] font-black bg-amber-50 text-amber-600 border border-amber-100 uppercase tracking-tight">Pendente</span>;
      case 'OVERDUE':
