                           className="w-12 h-12 flex items-center justify-center bg-slate-50 border border-slate-200 rounded-xl text-center text-xl outline-none focus:ring-2 focus:ring-blue-500"
                         />
                         <input 
                           type="text" 
                           value={quickCatName}
                           onChange={(e) => setQuickCatName(e.target.value)}
                           className="flex-1 px-4 h-12 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500"
                           placeholder="Nome..."
                           autoFocus
                         />
                       </div>
                       <div className="flex gap-2">
                         <button onClick={handleQuickSaveCategory} className="flex-1 py-2 bg-blue-600 text-white text-[10px] font-black uppercase rounded-lg">Confirmar</button>
                         <button onClick={() => setShowQuickCategoryForm(false)} className="flex-1 py-2 bg-slate-100 text-slate-500 text-[10px] font-black uppercase rounded-lg">Voltar</button>
                       </div>
