                      {categories.filter(cat => cat.type === formType).map(cat => (
                        <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>
                      ))}
                    </select>
                  )}
                </div>
              </div>

              <div className="pt-4">
                <button 
                  onClick={handleSaveTransaction}
                  className="w-full py-5 bg-slate-900 hover:bg-black text-white rounded-[24px] font-black text-xs uppercase tracking-widest transition-all shadow-xl active:scale-[0.98]"
