              >
                Fechar Gestor
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Transaction Entry Modal (Simplified) */}
      {showTransactionModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm">
          <div className="bg-white rounded-[40px] w-full max-w-lg shadow-2xl animate-scaleIn overflow-hidden border border-white/20">
            <div className="px-8 py-6 border-b flex items-center justify-between bg-slate-50">
              <div>
                <h3 className="text-xl font-black text-slate-900 tracking-tight">{editingTransaction ? 'Editar Registro' : 'Novo Lançamento'}</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Insira os dados da operação</p>
              </div>
              <button onClick={closeTransactionModal} className="w-10 h-10 flex items-center justify-center text-slate-400 hover:text-slate-900 hover:bg-slate-200 rounded-2xl transition-all">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              </button>
            </div>

            <div className="p-8 space-y-6">
              <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200">
                 <button 
                   onClick={() => setFormType('EXPENSE')}
                   className={`flex-1 py-3 rounded-xl text-xs font-black uppercase transition-all ${formType === 'EXPENSE' ? 'bg-rose-500 text-white shadow-lg' : 'text-slate-500'}`}
                 >
                   Saída
                 </button>
                 <button 
                   onClick={() => setFormType('INCOME')}
                   className={`flex-1 py-3 rounded-xl text-xs font-black uppercase transition-all ${formType === 'INCOME' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-500'}`}
                 >
                   Entrada
                 </button>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Descrição</label>
                <input 
                  type="text" 
                  value={formDescription}
                  onChange={(e) => setFormDescription(e.target.value)}
                  className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/10 font-bold text-slate-900" 
                  placeholder="Ex: Pagamento Internet, Venda X..." 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Valor (MZN)</label>
                  <input 
                    type="number" 
                    value={formAmount}
                    onChange={(e) => setFormAmount(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/10 font-black text-slate-900" 
                    placeholder="0.00" 
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Data</label>
                  <input 
                    type="date" 
                    value={formDate}
                    onChange={(e) => setFormDate(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/10 font-bold text-slate-900"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Status</label>
                  <select 
                    value={formStatus}
                    onChange={(e) => setFormStatus(e.target.value as TransactionStatus)}
                    className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/10 font-bold text-slate-900 appearance-none"
                  >
                    <option value="COMPLETED">Efetivado</option>
                    <option value="PENDING">Pendente</option>
                    <option value="OVERDUE">Atrasado</option>
                  </select>
                </div>
                <div className="relative">
                  <div className="flex justify-between items-center mb-2 ml-1">
                    <label className="block text-[10px] font-black text-slate-400 uppercase">Categoria</label>
                    <button 
                      onClick={() => setShowQuickCategoryForm(true)}
                      className="text-[9px] font-black text-blue-600 uppercase hover:text-blue-700"
                    >
                      + Criar Nova
                    </button>
                  </div>

                  {showQuickCategoryForm ? (
                    <div className="absolute inset-x-0 bottom-0 z-20 bg-white p-4 rounded-3xl border border-blue-200 shadow-2xl animate-slideDown">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-3">Rápida Categoria</p>
                       <div className="flex gap-2 mb-3">
                         <input 
                           type="text" 
                           value={quickCatIcon}
                           onChange={(e) => setQuickCatIcon(e.target.value)}
                           className="w-12 h-12 bg-slate-50 border border-slate-200 rounded-xl text-center text-xl outline-none"
                         />
                         <input 
                           type="text" 
                           value={quickCatName}
                           onChange={(e) => setQuickCatName(e.target.value)}
                           className="flex-1 px-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none"
                           placeholder="Nome..."
                         />
                       </div>
                       <div className="flex gap-2">
                         <button onClick={handleQuickSaveCategory} className="flex-1 py-2 bg-blue-600 text-white text-[10px] font-black uppercase rounded-lg">Salvar</button>
                         <button onClick={() => setShowQuickCategoryForm(false)} className="flex-1 py-2 bg-slate-100 text-slate-500 text-[10px] font-black uppercase rounded-lg">Cancelar</button>
                       </div>
                    </div>
                  ) : (
                    <select 
                      value={formCategoryId}
                      onChange={(e) => setFormCategoryId(e.target.value)}
                      className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/10 font-bold text-slate-900 appearance-none"
                    >
                      <option value="">Selecione...</option>
                      {categories.filter(cat => cat.type === formType).map(cat => (
                        <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>
                      ))}
                    </select>
                  )}
                </div>
              </div>

              <div className="pt-4">
                <button 
                  onClick={handleSaveTransaction}
                  className="w-full py-5 bg-slate-900 hover:bg-black text-white rounded-[24px] font-black text-xs uppercase tracking-widest transition-all shadow-xl active:scale-[0.98]"
                >
                  {editingTransaction ? 'Atualizar Dados' : 'Confirmar Registro'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { AccountType, Transaction, Category, TransactionType, TransactionStatus } from '../types';

export const TransactionsPage: React.FC<{ mode: AccountType }> = ({ mode }) => {
  const [showTransactionModal, setShowTransactionModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [showQuickCategoryForm, setShowQuickCategoryForm] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  // Search & Filter States
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [filterStatus, setFilterStatus] = useState<TransactionStatus | 'ALL'>('ALL');

  // State for Transactions
  const [transactions, setTransactions] = useState<Transaction[]>([
    { id: '1', amount: 4500, description: 'Venda de Produto A', date: '2024-05-20', type: 'INCOME', status: 'COMPLETED', categoryId: '2', tenantId: 't1' },
    { id: '2', amount: 1200, description: 'Fornecedor de Embalagens', date: '2024-05-19', type: 'EXPENSE', status: 'PENDING', categoryId: '4', tenantId: 't1' },
    { id: '3', amount: 35000, description: 'Aluguel Escritório', date: '2024-05-15', type: 'EXPENSE', status: 'COMPLETED', categoryId: '3', tenantId: 't1' },
    { id: '4', amount: 15000, description: 'Consultoria Mensal', date: '2024-05-10', type: 'INCOME', status: 'OVERDUE', categoryId: '2', tenantId: 't1' },
  ]);

  // State for Categories
  const [categories, setCategories] = useState<Category[]>([
    { id: '1', name: 'Salário', icon: '💰', color: 'bg-emerald-500', type: 'INCOME' },
    { id: '2', name: 'Vendas', icon: '🛒', color: 'bg-emerald-500', type: 'INCOME' },
    { id: '3', name: 'Aluguel', icon: '🏠', color: 'bg-rose-500', type: 'EXPENSE' },
    { id: '4', name: 'Alimentação', icon: '🍔', color: 'bg-rose-500', type: 'EXPENSE' },
    { id: '5', name: 'Transporte', icon: '🚗', color: 'bg-rose-500', type: 'EXPENSE' },
  ]);

  // Derived filtered transactions
  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filterStatus === 'ALL' || t.status === filterStatus;
      const tDate = new Date(t.date);
      const matchesStart = !filterStartDate || tDate >= new Date(filterStartDate);
      const matchesEnd = !filterEndDate || tDate <= new Date(filterEndDate);

      return matchesSearch && matchesStatus && matchesStart && matchesEnd;
    });
  }, [transactions, searchTerm, filterStatus, filterStartDate, filterEndDate]);

  // Transaction Form State
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formDescription, setFormDescription] = useState('');
  const [formAmount, setFormAmount] = useState<number | string>('');
  const [formType, setFormType] = useState<TransactionType>('EXPENSE');
  const [formStatus, setFormStatus] = useState<TransactionStatus>('COMPLETED');
  const [formCategoryId, setFormCategoryId] = useState('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);

  // Category Form State
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [newCatName, setNewCatName] = useState('');
  const [newCatType, setNewCatType] = useState<TransactionType>('EXPENSE');
  const [newCatIcon, setNewCatIcon] = useState('📁');

  // Quick Category Mini-Form State
  const [quickCatName, setQuickCatName] = useState('');
  const [quickCatIcon, setQuickCatIcon] = useState('✨');

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) return;

    if (editingTransaction) {
      setTransactions(transactions.map(t => 
        t.id === editingTransaction.id 
        ? { ...t, description: formDescription, amount: Number(formAmount), type: formType, status: formStatus, categoryId: formCategoryId, date: formDate } 
        : t
      ));
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        amount: Number(formAmount),
        description: formDescription,
        date: formDate,
        type: formType,
        status: formStatus,
        categoryId: formCategoryId,
        tenantId: 't1'
      };
      setTransactions([newTransaction, ...transactions]);
    }
    closeTransactionModal();
  };

  const closeTransactionModal = () => {
    setShowTransactionModal(false);
    setShowQuickCategoryForm(false);
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormType('EXPENSE');
    setFormStatus('COMPLETED');
    setFormCategoryId('');
    setFormDate(new Date().toISOString().split('T')[0]);
  };

  const startEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setFormDescription(t.description);
    setFormAmount(t.amount);
    setFormType(t.type);
    setFormStatus(t.status);
    setFormCategoryId(t.categoryId);
    setFormDate(t.date);
    setShowTransactionModal(true);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Deseja realmente excluir este lançamento?')) {
      setTransactions(transactions.filter(t => t.id !== id));
    }
  };

  const handleSaveCategory = () => {
    if (!newCatName.trim()) return;

    if (editingCategory) {
      setCategories(categories.map(c => c.id === editingCategory.id ? { ...c, name: newCatName, type: newCatType, icon: newCatIcon } : c));
    } else {
      const newCat: Category = {
        id: Math.random().toString(36).substr(2, 9),
        name: newCatName,
        type: newCatType,
        icon: newCatIcon,
        color: newCatType === 'INCOME' ? 'bg-emerald-500' : 'bg-rose-500'
      };
      setCategories([...categories, newCat]);
    }
    resetCategoryForm();
  };

  const handleQuickSaveCategory = () => {
    if (!quickCatName.trim()) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newCat: Category = {
      id: newId,
      name: quickCatName,
      type: formType, 
      icon: quickCatIcon,
      color: formType === 'INCOME' ? 'bg-emerald-500' : 'bg-rose-500'
    };

    setCategories([...categories, newCat]);
    setFormCategoryId(newId); 
    setQuickCatName('');
    setQuickCatIcon('✨');
    setShowQuickCategoryForm(false);
  };

  const deleteCategory = (id: string) => {
    if (confirm('Excluir esta categoria? Transações vinculadas poderão ficar órfãs.')) {
      setCategories(categories.filter(c => c.id !== id));
    }
  };

  const resetCategoryForm = () => {
    setEditingCategory(null);
    setNewCatName('');
    setNewCatType('EXPENSE');
    setNewCatIcon('📁');
  };

  const startEditCategory = (cat: Category) => {
    setEditingCategory(cat);
    setNewCatName(cat.name);
    setNewCatType(cat.type);
    setNewCatIcon(cat.icon);
  };

  const openQuickExpenseModal = () => {
    setFormType('EXPENSE');
    const firstExpenseCat = categories.find(c => c.type === 'EXPENSE');
    setFormCategoryId(firstExpenseCat?.id || '');
    setShowTransactionModal(true);
  };

  const clearFilters = () => {
    setSearchTerm('');
    setFilterStartDate('');
    setFilterEndDate('');
    setFilterStatus('ALL');
  };

  const getStatusBadge = (status: TransactionStatus) => {
    switch (status) {
      case 'COMPLETED':
        return <span className="px-3 py-1 rounded-full text-[10px] font-black bg-emerald-50 text-emerald-600 border border-emerald-100 uppercase">Efetivado</span>;
      case 'PENDING':
        return <span className="px-3 py-1 rounded-full text-[10px] font-black bg-amber-50 text-amber-600 border border-amber-100 uppercase">Pendente</span>;
      case 'OVERDUE':
        return <span className="px-3 py-1 rounded-full text-[10px] font-black bg-rose-50 text-rose-600 border border-rose-100 uppercase">Atrasado</span>;
      default:
        return null;
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20">
      {/* Search and Action Bar */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div className="flex-1 max-w-xl w-full flex items-center gap-2">
          <div className="relative flex-1 group">
            <svg className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 transition-colors" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
            <input 
              type="text" 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Pesquisar por descrição..."
              className="w-full pl-12 pr-6 py-4 bg-white border border-slate-200 rounded-[24px] outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all font-medium text-slate-700 shadow-sm"
            />
          </div>
          <button 
            onClick={() => setShowFilters(!showFilters)}
            className={`p-4 rounded-[20px] transition-all flex items-center justify-center border ${showFilters ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-500/30' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50 shadow-sm'}`}
            title="Filtros Avançados"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="4" x2="20" y1="21" y2="21"/><line x1="4" x2="20" y1="3" y2="3"/><line x1="12" x2="20" y1="12" y2="12"/><line x1="4" x2="8" y1="12" y2="12"/><circle cx="10" cy="12" r="2"/></svg>
          </button>
        </div>

        <div className="flex flex-wrap gap-3 w-full lg:w-auto">
          <button 
            onClick={() => setShowCategoryModal(true)}
            className="flex-1 lg:flex-none px-6 py-4 bg-white border border-slate-200 text-slate-700 rounded-[20px] font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all shadow-sm flex items-center justify-center gap-2"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
            Categorias
          </button>

