    { id: '1', amount: 4500, description: 'Venda de Produto A', date: '2024-05-20', type: 'INCOME', status: 'COMPLETED', categoryId: '2', tenantId: 't1' },
    { id: '2', amount: 1200, description: 'Fornecedor de Embalagens', date: '2024-05-19', type: 'EXPENSE', status: 'PENDING', categoryId: '4', tenantId: 't1' },
    { id: '3', amount: 35000, description: 'Aluguel Escritório', date: '2024-05-15', type: 'EXPENSE', status: 'COMPLETED', categoryId: '3', tenantId: 't1' },
    { id: '4', amount: 15000, description: 'Consultoria Mensal', date: '2024-05-10', type: 'INCOME', status: 'OVERDUE', categoryId: '2', tenantId: 't1' },
  ]);

  // State for Categories
  const [categories, setCategories] = useState<Category[]>([
    { id: '1', name: 'Salário', icon: '💰', color: 'bg-emerald-500', type: 'INCOME' },
    { id: '2', name: 'Vendas', icon: '🛒', color: 'bg-emerald-500', type: 'INCOME' },
    { id: '3', name: 'Aluguel', icon: '🏠', color: 'bg-rose-500', type: 'EXPENSE' },
    { id: '4', name: 'Alimentação', icon: '🍔', color: 'bg-rose-500', type: 'EXPENSE' },
    { id: '5', name: 'Transporte', icon: '🚗', color: 'bg-rose-500', type: 'EXPENSE' },
  ]);

  // Count active filters (excluding default ALL status)
  const activeFilterCount = useMemo(() => {
    let count = 0;
    if (filterStartDate) count++;
    if (filterEndDate) count++;
    if (filterStatus !== 'ALL') count++;
    return count;
  }, [filterStartDate, filterEndDate, filterStatus]);

  // Derived filtered transactions
  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filterStatus === 'ALL' || t.status === filterStatus;

      // Date normalization for robust comparison
      const tDate = new Date(t.date).setHours(0,0,0,0);
      const matchesStart = !filterStartDate || tDate >= new Date(filterStartDate).setHours(0,0,0,0);
      const matchesEnd = !filterEndDate || tDate <= new Date(filterEndDate).setHours(0,0,0,0);

      return matchesSearch && matchesStatus && matchesStart && matchesEnd;
    });
  }, [transactions, searchTerm, filterStatus, filterStartDate, filterEndDate]);

  // Transaction Form States
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formDescription, setFormDescription] = useState('');
  const [formAmount, setFormAmount] = useState<number | string>('');
  const [formType, setFormType] = useState<TransactionType>('EXPENSE');
  const [formStatus, setFormStatus] = useState<TransactionStatus>('COMPLETED');
  const [formCategoryId, setFormCategoryId] = useState('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);

  // Category Form States
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [newCatName, setNewCatName] = useState('');
  const [newCatType, setNewCatType] = useState<TransactionType>('EXPENSE');
  const [newCatIcon, setNewCatIcon] = useState('📁');

  // Quick Category Mini-Form State
  const [quickCatName, setQuickCatName] = useState('');
  const [quickCatIcon, setQuickCatIcon] = useState('✨');

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) return;

    if (editingTransaction) {
      setTransactions(transactions.map(t => 
        t.id === editingTransaction.id 
        ? { ...t, description: formDescription, amount: Number(formAmount), type: formType, status: formStatus, categoryId: formCategoryId, date: formDate } 
        : t
      ));
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        amount: Number(formAmount),
        description: formDescription,
        date: formDate,
        type: formType,
        status: formStatus,
        categoryId: formCategoryId,
        tenantId: 't1'
      };
      setTransactions([newTransaction, ...transactions]);
    }
    closeTransactionModal();
  };

  const closeTransactionModal = () => {
    setShowTransactionModal(false);
    setShowQuickCategoryForm(false);
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormType('EXPENSE');
    setFormStatus('COMPLETED');
    setFormCategoryId('');
    setFormDate(new Date().toISOString().split('T')[0]);
  };

  const startEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setFormDescription(t.description);
    setFormAmount(t.amount);
    setFormType(t.type);
    setFormStatus(t.status);
    setFormCategoryId(t.categoryId);
    setFormDate(t.date);
    setShowTransactionModal(true);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Deseja realmente excluir este lançamento?')) {
      setTransactions(transactions.filter(t => t.id !== id));
    }
  };

  const handleSaveCategory = () => {
    if (!newCatName.trim()) return;

    if (editingCategory) {
      setCategories(categories.map(c => c.id === editingCategory.id ? { ...c, name: newCatName, type: newCatType, icon: newCatIcon } : c));
    } else {
      const newCat: Category = {
        id: Math.random().toString(36).substr(2, 9),
        name: newCatName,
        type: newCatType,
        icon: newCatIcon,
        color: newCatType === 'INCOME' ? 'bg-emerald-500' : 'bg-rose-500'
      };
      setCategories([...categories, newCat]);
    }
    resetCategoryForm();
  };

  const handleQuickSaveCategory = () => {
    if (!quickCatName.trim()) return;
    const newId = Math.random().toString(36).substr(2, 9);
    const newCat: Category = {
      id: newId,
      name: quickCatName,
      type: formType, 
      icon: quickCatIcon,
      color: formType === 'INCOME' ? 'bg-emerald-500' : 'bg-rose-500'
    };
    setCategories([...categories, newCat]);
    setFormCategoryId(newId); 
    setQuickCatName('');
    setQuickCatIcon('✨');
    setShowQuickCategoryForm(false);
  };

  const deleteCategory = (id: string) => {
    if (confirm('Excluir esta categoria? Transações vinculadas poderão ficar órfãs.')) {
      setCategories(categories.filter(c => c.id !== id));
    }
  };

  const resetCategoryForm = () => {
    setEditingCategory(null);
    setNewCatName('');
    setNewCatType('EXPENSE');
    setNewCatIcon('📁');
  };

  const startEditCategory = (cat: Category) => {
    setEditingCategory(cat);
    setNewCatName(cat.name);
    setNewCatType(cat.type);
    setNewCatIcon(cat.icon);
  };

  const openQuickExpenseModal = () => {
    setFormType('EXPENSE');
    const firstExpenseCat = categories.find(c => c.type === 'EXPENSE');
    setFormCategoryId(firstExpenseCat?.id || '');
    setShowTransactionModal(true);
  };

  const clearFilters = () => {
    setSearchTerm('');
    setFilterStartDate('');
    setFilterEndDate('');
    setFilterStatus('ALL');
  };

  const getStatusBadge = (status: TransactionStatus) => {
    switch (status) {
      case 'COMPLETED':
        return <span className="px-3 py-1 rounded-full text-[10px] font-black bg-emerald-50 text-emerald-600 border border-emerald-100 uppercase">Efetivado</span>;
      case 'PENDING':
        return <span className="px-3 py-1 rounded-full text-[10px] font-black bg-amber-50 text-amber-600 border border-amber-100 uppercase">Pendente</span>;
      case 'OVERDUE':
        return <span className="px-3 py-1 rounded-full text-[10px] font-black bg-rose-50 text-rose-600 border border-rose-100 uppercase">Atrasado</span>;
      default:
        return null;
    }
  };

  const getStatusLabel = (status: TransactionStatus | 'ALL') => {
    if (status === 'ALL') return 'Todos';
    if (status === 'COMPLETED') return 'Efetivado';
    if (status === 'PENDING') return 'Pendente';
    return 'Atrasado';
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20">
      {/* Search and Action Bar */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div className="flex-1 max-w-2xl w-full">
          <div className="flex items-center gap-3">
            <div className="relative flex-1 group">
              <svg className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 transition-colors" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
              <input 
                type="text" 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="Pesquisar por descrição..."
                className="w-full pl-12 pr-6 py-4 bg-white border border-slate-200 rounded-[24px] outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all font-medium text-slate-700 shadow-sm"
              />
            </div>
            <button 
              onClick={() => setShowFilters(!showFilters)}
              className={`relative p-4 rounded-[22px] transition-all flex items-center justify-center border shadow-sm ${showFilters ? 'bg-blue-600 border-blue-600 text-white shadow-blue-500/20' : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'}`}
              title="Filtros Avançados"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="21" x2="4" y1="4" y2="4"/><line x1="21" x2="4" y1="12" y2="12"/><line x1="21" x2="4" y1="20" y2="20"/><circle cx="7" cy="4" r="2"/><circle cx="17" cy="12" r="2"/><circle cx="7" cy="20" r="2"/></svg>
              {activeFilterCount > 0 && (
                <span className="absolute -top-1 -right-1 w-5 h-5 bg-rose-500 text-white text-[10px] font-black rounded-full flex items-center justify-center border-2 border-white shadow-sm">
                  {activeFilterCount}
                </span>
              )}
            </button>
          </div>

          {/* Active Filter Tags */}
          {activeFilterCount > 0 && (
            <div className="flex flex-wrap gap-2 mt-3 animate-fadeIn">
              {filterStartDate && (
                <button onClick={() => setFilterStartDate('')} className="flex items-center gap-2 px-3 py-1.5 bg-blue-50 text-blue-600 rounded-full text-[10px] font-black uppercase tracking-wider border border-blue-100 hover:bg-blue-100 transition-colors">
                  Início: {new Date(filterStartDate).toLocaleDateString()}
                  <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
                </button>
              )}
              {filterEndDate && (
                <button onClick={() => setFilterEndDate('')} className="flex items-center gap-2 px-3 py-1.5 bg-blue-50 text-blue-600 rounded-full text-[10px] font-black uppercase tracking-wider border border-blue-100 hover:bg-blue-100 transition-colors">
                  Fim: {new Date(filterEndDate).toLocaleDateString()}
                  <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
                </button>
              )}
              {filterStatus !== 'ALL' && (
                <button onClick={() => setFilterStatus('ALL')} className="flex items-center gap-2 px-3 py-1.5 bg-blue-50 text-blue-600 rounded-full text-[10px] font-black uppercase tracking-wider border border-blue-100 hover:bg-blue-100 transition-colors">
                  Status: {getStatusLabel(filterStatus)}
                  <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
                </button>
              )}
              <button onClick={clearFilters} className="px-3 py-1.5 text-slate-400 hover:text-rose-500 text-[10px] font-black uppercase tracking-wider transition-colors">
                Limpar Tudo
              </button>
            </div>
          )}
        </div>

        <div className="flex flex-wrap gap-3 w-full lg:w-auto">
          <button 
            onClick={() => setShowCategoryModal(true)}
            className="flex-1 lg:flex-none px-6 py-4 bg-white border border-slate-200 text-slate-700 rounded-[22px] font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all shadow-sm flex items-center justify-center gap-2"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
            Categorias
          </button>

          <button 
            onClick={openQuickExpenseModal}
            className="flex-1 lg:flex-none bg-rose-500 hover:bg-rose-600 text-white px-6 py-4 rounded-[22px] font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 transition-all shadow-lg shadow-rose-500/20 active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/></svg>
            Novo Gasto
          </button>

          <button 
            onClick={() => setShowTransactionModal(true)}
            className="flex-1 lg:flex-none bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-[22px] font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 transition-all shadow-lg shadow-blue-500/20 active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
            Novo Lançamento
          </button>
        </div>
      </div>

      {/* Advanced Filter Panel - UI Refined */}
      {showFilters && (
        <div className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-xl shadow-slate-200/50 animate-slideDown grid grid-cols-1 md:grid-cols-12 gap-8 items-end">
          <div className="md:col-span-5 space-y-3">
            <div className="flex items-center gap-2 mb-1">
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="text-blue-500"><rect width="18" height="18" x="3" y="4" rx="2" ry="2"/><line x1="16" x2="16" y1="2" y2="6"/><line x1="8" x2="8" y1="2" y2="6"/><line x1="3" x2="21" y1="10" y2="10"/></svg>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Filtrar por Período</label>
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-[9px] font-black text-slate-300 uppercase pointer-events-none">DE</span>
                <input 
                  type="date" 
                  value={filterStartDate}
                  onChange={(e) => setFilterStartDate(e.target.value)}
                  className="w-full pl-9 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:ring-4 focus:ring-blue-500/10 outline-none transition-all"
                />
              </div>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-[9px] font-black text-slate-300 uppercase pointer-events-none">ATÉ</span>
                <input 
                  type="date" 
                  value={filterEndDate}
                  onChange={(e) => setFilterEndDate(e.target.value)}
                  className="w-full pl-9 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:ring-4 focus:ring-blue-500/10 outline-none transition-all"
                />
              </div>
            </div>
          </div>

          <div className="md:col-span-4 space-y-3">
            <div className="flex items-center gap-2 mb-1">
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="text-blue-500"><path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z"/><path d="m9 12 2 2 4-4"/></svg>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Status do Registro</label>
            </div>
            <div className="flex gap-1 p-1 bg-slate-100 rounded-xl">
              {(['ALL', 'PENDING', 'COMPLETED', 'OVERDUE'] as const).map((status) => (
                <button
                  key={status}
                  onClick={() => setFilterStatus(status)}
                  className={`flex-1 py-2.5 rounded-lg text-[9px] font-black uppercase transition-all ${filterStatus === status ? 'bg-white text-blue-600 shadow-sm border border-slate-200' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  {status === 'ALL' ? 'Todos' : status === 'PENDING' ? 'Pend.' : status === 'COMPLETED' ? 'Efet.' : 'Atras.'}
                </button>
              ))}
            </div>
          </div>

          <div className="md:col-span-3">
            <button 
              onClick={clearFilters}
              className="w-full py-3.5 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              Limpar Filtros
            </button>
          </div>
        </div>
      )}

      {/* Main Table Container */}
      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Valor</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredTransactions.map((t) => {
                const category = categories.find(c => c.id === t.categoryId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-8 py-6 text-sm font-bold text-slate-400">
                       {new Date(t.date).toLocaleDateString('pt-MZ', { day: '2-digit', month: 'short' })}
                    </td>
                    <td className="px-8 py-6">
                      <p className="text-sm font-black text-slate-900">{t.description}</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter mt-1">ID: {t.id}</p>
                    </td>
                    <td className="px-8 py-6">
                      <span className="inline-flex items-center gap-2 px-3 py-1.5 rounded-xl text-xs font-black bg-slate-100 text-slate-700 border border-slate-200">
                        <span className="text-base">{category?.icon || '📁'}</span>
                        {category?.name || 'Sem Categoria'}
                      </span>
                    </td>
                    <td className="px-8 py-6">
                      {getStatusBadge(t.status)}
                    </td>
                    <td className={`px-8 py-6 text-base font-black text-right whitespace-nowrap ${t.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>
                      {t.type === 'INCOME' ? '+' : '-'} {t.amount.toLocaleString('pt-MZ')} <span className="text-[10px] opacity-60">MZN</span>
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => startEditTransaction(t)} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all">
                           <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                         </button>
                         <button onClick={() => deleteTransaction(t.id)} className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all">
                           <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
                         </button>
                       </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        {/* Empty State Refined */}
        {filteredTransactions.length === 0 && (
          <div className="py-24 text-center flex flex-col items-center justify-center">
             <div className="w-20 h-20 bg-slate-50 rounded-[30px] flex items-center justify-center text-slate-200 mb-6 border-2 border-dashed border-slate-100">
               <svg xmlns="http://www.w3.org/2000/svg" width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
             </div>
             <h4 className="text-slate-900 font-black text-lg">Nenhum registro encontrado</h4>
             <p className="text-slate-400 font-medium text-sm mt-1">Tente ajustar seus filtros ou termos de pesquisa.</p>
             <button 
               onClick={clearFilters} 
               className="mt-6 px-6 py-2.5 bg-blue-50 text-blue-600 text-xs font-black uppercase tracking-widest rounded-full border border-blue-100 hover:bg-blue-100 transition-all shadow-sm"
             >
               Remover todos os filtros
             </button>
          </div>
        )}
