      const tDate = new Date(t.date).setHours(0,0,0,0);
      const matchesStart = !filterStartDate || tDate >= new Date(filterStartDate).setHours(0,0,0,0);
      const matchesEnd = !filterEndDate || tDate <= new Date(filterEndDate).setHours(0,0,0,0);
      return matchesSearch && matchesStatus && matchesStart && matchesEnd;
    });
  }, [transactions, searchTerm, filterStatus, filterStartDate, filterEndDate]);

  // Transaction Form States
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formDescription, setFormDescription] = useState('');
  const [formAmount, setFormAmount] = useState<number | string>('');
  const [formType, setFormType] = useState<TransactionType>('EXPENSE');
  const [formStatus, setFormStatus] = useState<TransactionStatus>('COMPLETED');
  const [formCategoryId, setFormCategoryId] = useState('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);

  const toggleTransactionStatus = (id: string) => {
    setTransactions(transactions.map(t => {
      if (t.id === id) {
        const nextStatus: TransactionStatus = t.status === 'COMPLETED' ? 'PENDING' : 'COMPLETED';
        return { ...t, status: nextStatus };
      }
      return t;
    }));
  };

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) return;
    if (editingTransaction) {
      setTransactions(transactions.map(t => 
        t.id === editingTransaction.id 
        ? { ...t, description: formDescription, amount: Number(formAmount), type: formType, status: formStatus, categoryId: formCategoryId, date: formDate } 
        : t
      ));
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        amount: Number(formAmount),
        description: formDescription,
        date: formDate,
        type: formType,
        status: formStatus,
        categoryId: formCategoryId,
        tenantId: 't1'
      };
      setTransactions([newTransaction, ...transactions]);
    }
    closeTransactionModal();
  };

  const closeTransactionModal = () => {
    setShowTransactionModal(false);
    setShowQuickCategoryForm(false);
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormType('EXPENSE');
    setFormStatus('COMPLETED');
    setFormCategoryId('');
    setFormDate(new Date().toISOString().split('T')[0]);
  };

  const startEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setFormDescription(t.description);
    setFormAmount(t.amount);
    setFormType(t.type);
    setFormStatus(t.status);
    setFormCategoryId(t.categoryId);
    setFormDate(t.date);
    setShowTransactionModal(true);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Deseja realmente excluir este lançamento?')) {
      setTransactions(transactions.filter(t => t.id !== id));
    }
  };

  const clearFilters = () => {
    setSearchTerm('');
    setFilterStartDate('');
    setFilterEndDate('');
    setFilterStatus('ALL');
  };

  const getStatusBadge = (t: Transaction) => {
    const status = t.status;
    let colorClass = "";
    let label = "";

    switch (status) {
      case 'COMPLETED':
        colorClass = "bg-emerald-50 text-emerald-600 border-emerald-100";
        label = "Efetivado";
        break;
      case 'PENDING':
        colorClass = "bg-amber-50 text-amber-600 border-amber-100";
        label = "Pendente";
        break;
      case 'OVERDUE':
        colorClass = "bg-rose-50 text-rose-600 border-rose-100";
        label = "Atrasado";
        break;
    }

    return (
      <button 
        onClick={(e) => { e.stopPropagation(); toggleTransactionStatus(t.id); }}
        className={`px-3 py-1.5 rounded-full text-[10px] font-black border uppercase transition-all hover:shadow-md active:scale-95 ${colorClass}`}
        title="Clique para alternar entre Pendente e Efetivado"
      >
        {label}
      </button>
    );
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20">
      {/* Search and Action Bar */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div className="flex-1 max-w-2xl w-full">
          <div className="flex items-center gap-3">
            <div className="relative flex-1 group">
              <svg className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 transition-colors" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
              <input 
                type="text" 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="Pesquisar por descrição..."
                className="w-full pl-12 pr-6 py-4 bg-white border border-slate-200 rounded-[24px] outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all font-medium text-slate-700 shadow-sm"
              />
            </div>
            <button 
              onClick={() => setShowFilters(!showFilters)}
              className={`relative p-4 rounded-[22px] transition-all flex items-center justify-center border shadow-sm ${showFilters ? 'bg-blue-600 border-blue-600 text-white shadow-blue-500/20' : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="21" x2="4" y1="4" y2="4"/><line x1="21" x2="4" y1="12" y2="12"/><line x1="21" x2="4" y1="20" y2="20"/><circle cx="7" cy="4" r="2"/><circle cx="17" cy="12" r="2"/><circle cx="7" cy="20" r="2"/></svg>
              {activeFilterCount > 0 && <span className="absolute -top-1 -right-1 w-5 h-5 bg-rose-500 text-white text-[10px] font-black rounded-full flex items-center justify-center border-2 border-white shadow-sm">{activeFilterCount}</span>}
            </button>
          </div>
        </div>

        <div className="flex flex-wrap gap-3 w-full lg:w-auto">
          <button onClick={() => setShowCategoryModal(true)} className="flex-1 lg:flex-none px-6 py-4 bg-white border border-slate-200 text-slate-700 rounded-[22px] font-black text-xs uppercase hover:bg-slate-50 transition-all shadow-sm flex items-center justify-center gap-2">Categorias</button>
          <button onClick={() => setShowTransactionModal(true)} className="flex-1 lg:flex-none bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-[22px] font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 transition-all shadow-lg shadow-blue-500/20 active:scale-95">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
            Novo Lançamento
          </button>
        </div>
      </div>

      {/* Filter Panel */}
      {showFilters && (
        <div className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-xl shadow-slate-200/50 animate-slideDown grid grid-cols-1 md:grid-cols-12 gap-8 items-end">
          <div className="md:col-span-5 space-y-3">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Filtrar por Período</label>
            <div className="grid grid-cols-2 gap-3">
              <input type="date" value={filterStartDate} onChange={(e) => setFilterStartDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none" />
              <input type="date" value={filterEndDate} onChange={(e) => setFilterEndDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none" />
            </div>
          </div>
          <div className="md:col-span-4 space-y-3">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Status do Registro</label>
            <div className="flex gap-1 p-1 bg-slate-100 rounded-xl">
              {(['ALL', 'PENDING', 'COMPLETED', 'OVERDUE'] as const).map((status) => (
                <button key={status} onClick={() => setFilterStatus(status)} className={`flex-1 py-2.5 rounded-lg text-[9px] font-black uppercase transition-all ${filterStatus === status ? 'bg-white text-blue-600 shadow-sm border border-slate-200' : 'text-slate-400 hover:text-slate-600'}`}>{status === 'ALL' ? 'Todos' : status === 'PENDING' ? 'Pend.' : status === 'COMPLETED' ? 'Efet.' : 'Atras.'}</button>
              ))}
            </div>
          </div>
          <div className="md:col-span-3">
            <button onClick={clearFilters} className="w-full py-3.5 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl text-xs font-black uppercase tracking-widest transition-all">Limpar Filtros</button>
          </div>
        </div>
      )}

      {/* Main Table */}
      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase">Data</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase">Descrição</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase">Categoria</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase">Status</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase text-right">Valor</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredTransactions.map((t) => {
                const category = categories.find(c => c.id === t.categoryId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-8 py-6 text-sm font-bold text-slate-400">{new Date(t.date).toLocaleDateString('pt-MZ', { day: '2-digit', month: 'short' })}</td>
                    <td className="px-8 py-6">
                      <p className="text-sm font-black text-slate-900">{t.description}</p>
                    </td>
                    <td className="px-8 py-6">
                      <span className="inline-flex items-center gap-2 px-3 py-1.5 rounded-xl text-xs font-black bg-slate-100 text-slate-700 border border-slate-200">
                        <span>{category?.icon || '📁'}</span>
                        {category?.name || 'Sem Categoria'}
                      </span>
                    </td>
                    <td className="px-8 py-6">{getStatusBadge(t)}</td>
                    <td className={`px-8 py-6 text-base font-black text-right whitespace-nowrap ${t.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>
                      {t.type === 'INCOME' ? '+' : '-'} {t.amount.toLocaleString('pt-MZ')} <span className="text-[10px] opacity-60">MZN</span>
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => startEditTransaction(t)} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all">
                           <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                         </button>
                         <button onClick={() => deleteTransaction(t.id)} className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all">
                           <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
                         </button>
                       </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Transaction Entry Modal */}
      {showTransactionModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm">
          <div className="bg-white rounded-[40px] w-full max-w-lg shadow-2xl animate-scaleIn overflow-hidden">
            <div className="px-8 py-6 border-b flex items-center justify-between bg-slate-50">
              <h3 className="text-xl font-black text-slate-900">{editingTransaction ? 'Editar Registro' : 'Novo Lançamento'}</h3>
              <button onClick={closeTransactionModal} className="w-10 h-10 flex items-center justify-center text-slate-400 hover:bg-slate-200 rounded-2xl transition-all">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              </button>
            </div>

            <div className="p-8 space-y-6">
              {/* Type Switcher */}
              <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200">
                 <button onClick={() => setFormType('EXPENSE')} className={`flex-1 py-3 rounded-xl text-xs font-black uppercase transition-all ${formType === 'EXPENSE' ? 'bg-rose-500 text-white shadow-lg' : 'text-slate-500'}`}>Saída</button>
                 <button onClick={() => setFormType('INCOME')} className={`flex-1 py-3 rounded-xl text-xs font-black uppercase transition-all ${formType === 'INCOME' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-500'}`}>Entrada</button>
              </div>

              {/* Status Stepper / Segmented Control */}
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Status da Transação</label>
                <div className="flex bg-slate-100 p-1 rounded-2xl gap-1">
                  {(['PENDING', 'COMPLETED', 'OVERDUE'] as TransactionStatus[]).map((s) => (
                    <button 
                      key={s} 
                      onClick={() => setFormStatus(s)}
                      className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex flex-col items-center gap-1 ${
                        formStatus === s 
                          ? s === 'COMPLETED' ? 'bg-emerald-500 text-white' : s === 'PENDING' ? 'bg-amber-500 text-white' : 'bg-rose-500 text-white'
                          : 'text-slate-400 hover:text-slate-600'
                      }`}
                    >
                      {s === 'COMPLETED' && <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6L9 17l-5-5"/></svg>}
                      {s === 'PENDING' && <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>}
                      {s === 'OVERDUE' && <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>}
                      {s === 'PENDING' ? 'Pendente' : s === 'COMPLETED' ? 'Efetivado' : 'Atrasado'}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Descrição</label>
                <input type="text" value={formDescription} onChange={(e) => setFormDescription(e.target.value)} className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/10 font-bold text-slate-900" placeholder="Ex: Pagamento Internet..." />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Valor (MZN)</label>
                  <input type="number" value={formAmount} onChange={(e) => setFormAmount(e.target.value)} className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/10 font-black text-slate-900" placeholder="0.00" />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Data</label>
                  <input type="date" value={formDate} onChange={(e) => setFormDate(e.target.value)} className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/10 font-bold text-slate-900" />
                </div>
              </div>

              <div className="relative">
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Categoria</label>
                <select value={formCategoryId} onChange={(e) => setFormCategoryId(e.target.value)} className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/10 font-bold text-slate-900 appearance-none">
                  <option value="">Selecione...</option>
                  {categories.filter(cat => cat.type === formType).map(cat => (
                    <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>
                  ))}
                </select>
              </div>

              <div className="pt-4">
                <button onClick={handleSaveTransaction} className="w-full py-5 bg-slate-900 hover:bg-black text-white rounded-[24px] font-black text-xs uppercase tracking-widest transition-all shadow-xl active:scale-[0.98]">
                  {editingTransaction ? 'Atualizar Registro' : 'Confirmar Lançamento'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts';

const categoryData = [
  { name: 'Infraestrutura', value: 4500, color: '#3b82f6' },
  { name: 'Operacional', value: 3000, color: '#10b981' },
  { name: 'Marketing', value: 2000, color: '#f59e0b' },
  { name: 'Pessoal', value: 5000, color: '#8b5cf6' },
];

const annualHistory = [
  { month: 'Junho', income: 60000, expense: 40000 },
  { month: 'Maio', income: 55000, expense: 42000 },
  { month: 'Abril', income: 50000, expense: 44000 },
  { month: 'Março', income: 45000, expense: 46000 },
];

export const ReportsPage: React.FC = () => {
  const [isExportingCSV, setIsExportingCSV] = useState(false);
  const [isExportingPDF, setIsExportingPDF] = useState(false);

  const exportToCSV = () => {
    setIsExportingCSV(true);

    // Simulação de delay para processamento
    setTimeout(() => {
      const headers = ['Mes', 'Entradas (MZN)', 'Saidas (MZN)', 'Resultado (MZN)'];
      const rows = annualHistory.map(item => [
        item.month,
        item.income,
        item.expense,
        item.income - item.expense
      ]);

      const csvContent = [
        headers.join(','),
        ...rows.map(row => row.join(','))
      ].join('\n');

      // Adiciona BOM para UTF-8 (garante compatibilidade com Excel)
      const blob = new Blob(['\ufeff' + csvContent], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement('a');
      const url = URL.createObjectURL(blob);

      link.setAttribute('href', url);
      link.setAttribute('download', `relatorio_anual_fintech_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      setIsExportingCSV(false);
    }, 800);
  };

  const handlePrintPDF = () => {
    setIsExportingPDF(true);
    // Pequeno delay para permitir que o navegador prepare o frame
    setTimeout(() => {
      window.print();
      setIsExportingPDF(false);
    }, 500);
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* Header com botões de ação - No-print esconde na exportação de PDF */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 no-print">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Relatórios Analíticos</h2>
          <p className="text-slate-500 font-medium">Entenda para onde seu dinheiro está indo de forma visual.</p>
        </div>
        <div className="flex gap-3">
           <button 
             onClick={exportToCSV}
             disabled={isExportingCSV}
             className="px-6 py-3 bg-white border border-slate-200 rounded-2xl font-bold text-sm hover:bg-slate-50 transition-all flex items-center gap-2 disabled:opacity-50"
           >
              {isExportingCSV ? (
                <div className="w-4 h-4 border-2 border-slate-300 border-t-blue-600 rounded-full animate-spin"></div>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
              )}
              {isExportingCSV ? 'Gerando CSV...' : 'Exportar CSV'}
           </button>
           <button 
             onClick={handlePrintPDF}
             disabled={isExportingPDF}
             className="px-6 py-3 bg-blue-600 text-white rounded-2xl font-bold text-sm hover:bg-blue-700 transition-all shadow-lg shadow-blue-500/20 flex items-center gap-2 disabled:opacity-50"
           >
              {isExportingPDF ? (
                <div className="w-4 h-4 border-2 border-blue-300 border-t-white rounded-full animate-spin"></div>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9V2h12v7"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
              )}
              {isExportingPDF ? 'Preparando...' : 'Gerar PDF'}
           </button>
        </div>
      </div>

      {/* Identificação de Relatório para o PDF (Só aparece no Print) */}
      <div className="hidden print:block mb-8 border-b-2 border-slate-900 pb-6">
          <div className="flex justify-between items-end">
              <div>
                  <h1 className="text-4xl font-black text-slate-900 uppercase">Relatório Financeiro Executivo</h1>
                  <p className="text-slate-500 font-bold mt-2">FINTECH SAAS - Inteligência de Escala</p>
              </div>
              <div className="text-right">
                  <p className="text-xs font-black uppercase text-slate-400">Data de Geração</p>
                  <p className="text-sm font-bold text-slate-900">{new Date().toLocaleDateString('pt-MZ')}</p>
              </div>
