export const ReportsPage: React.FC = () => {
  const [isExportingCSV, setIsExportingCSV] = useState(false);
  const [isExportingPDF, setIsExportingPDF] = useState(false);

  /**
   * Simulação de Serviço de Backend para Exportação
   * Em um cenário real, isso faria um fetch(URL_API + '/export/csv')
   */
  const fetchExportDataFromBackend = async () => {
    return new Promise((resolve) => {
      setTimeout(() => {
        // Simulando retorno de um dataset mais completo do banco de dados
        const fullData = annualHistory.map(item => ({
          ...item,
          balance: item.income - item.expense,
          status: 'FECHADO',
          date: `01/2024` // Exemplo
        }));
        resolve(fullData);
      }, 1200);
    });
  };

  const handleExportCSV = async () => {
    try {
      setIsExportingCSV(true);

      // 1. Conecta ao "backend" para obter os dados processados
      const data: any = await fetchExportDataFromBackend();

      // 2. Constrói o conteúdo CSV
      const headers = ['Mês', 'Receitas (MZN)', 'Despesas (MZN)', 'Saldo Líquido (MZN)', 'Status de Fechamento'];
      const rows = data.map((item: any) => [
        item.month,
        item.income.toFixed(2),
        item.expense.toFixed(2),
        item.balance.toFixed(2),
        item.status
      ]);

      const csvContent = [
        headers.join(';'), // Ponto e vírgula é padrão para Excel em PT-BR/MZ
        ...rows.map((row: any) => row.join(';'))
      ].join('\n');

      // 3. Cria o Blob com BOM (Byte Order Mark) para garantir UTF-8 no Excel
      const BOM = '\uFEFF';
      const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });

      // 4. Trigger do Download
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `FINTECH_Relatorio_Financeiro_${new Date().getTime()}.csv`);
      document.body.appendChild(link);
      link.click();

      // Cleanup
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error("Erro na exportação CSV:", error);
      alert("Falha ao gerar arquivo CSV. Verifique a conexão com o servidor.");
    } finally {
      setIsExportingCSV(false);
    }
  };

