                  <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m18 15-6-6-6 6"/></svg>
                </div>
                <span className="text-lg font-black text-emerald-600 whitespace-nowrap">{totals.income.toLocaleString('pt-MZ')} <span className="text-xs opacity-60">MZN</span></span>
              </div>
            </div>

            <div className="w-px h-10 bg-slate-200 hidden md:block"></div>

            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Despesas</span>
