          <div className={`p-6 rounded-[32px] border flex flex-col items-center md:items-end min-w-[200px] transition-all duration-500 ${dailyBalance >= 0 ? 'bg-emerald-500 border-emerald-400 shadow-lg shadow-emerald-500/20 text-white' : 'bg-rose-500 border-rose-400 shadow-lg shadow-rose-500/20 text-white'}`}>
