import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";

interface Message {
  role: 'user' | 'assistant';
  text: string;
  isThinking?: boolean;
  sources?: { web: { uri: string; title: string } }[];
}

export const AIAssistant: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', text: 'Olá! Sou seu assistente FINTECH AI. Como posso ajudar com sua estratégia financeira ou dados de mercado hoje?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const aiPlaceholder: Message = { role: 'assistant', text: '', isThinking: true };
    setMessages(prev => [...prev, aiPlaceholder]);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const isMarketQuery = input.toLowerCase().includes('mercado') || 
                            input.toLowerCase().includes('hoje') || 
                            input.toLowerCase().includes('preço') ||
                            input.toLowerCase().includes('notícia');

      let response;
      if (isMarketQuery) {
        response = await ai.models.generateContent({
          model: "gemini-3-flash-preview",
          contents: input,
          config: {
            tools: [{ googleSearch: {} }],
            systemInstruction: "Você é um analista financeiro especialista no mercado Africano. Forneça dados precisos e atuais."
          }
        });
      } else {
        response = await ai.models.generateContent({
          model: "gemini-3-pro-preview",
          contents: input,
          config: {
            thinkingConfig: { thinkingBudget: 32768 },
            systemInstruction: "Você é um CFO sênior. Sua tarefa é analisar problemas financeiros complexos. Pense passo a passo."
          }
        });
      }

      const text = response.text || "Desculpe, não consegui processar agora.";
      const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

      setMessages(prev => {
        const last = [...prev];
        last[last.length - 1] = { role: 'assistant', text, isThinking: false, sources: sources as any };
        return last;
      });
    } catch (error) {
      setMessages(prev => {
        const last = [...prev];
        last[last.length - 1] = { role: 'assistant', text: "Erro ao conectar com a IA.", isThinking: false };
        return last;
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden animate-fadeIn">
      {/* AI Header */}
      <div className="bg-slate-950 p-6 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-orange-500 rounded-2xl flex items-center justify-center shadow-lg shadow-orange-500/20">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="text-white"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
          </div>
          <div>
            <h3 className="text-white font-black tracking-tight">FINTECH AI</h3>
            <p className="text-orange-500 text-[10px] font-black uppercase tracking-widest">Enterprise Intelligence Active</p>
          </div>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-6 md:p-10 space-y-8 scrollbar-hide bg-slate-50/50">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-slideUp`}>
            <div className={`max-w-[85%] md:max-w-[70%] rounded-[32px] p-6 shadow-sm border ${
              msg.role === 'user' 
                ? 'bg-orange-500 text-white border-orange-400 rounded-tr-none' 
                : 'bg-white text-slate-800 border-slate-100 rounded-tl-none'
            }`}>
              {msg.isThinking ? (
                <div className="flex items-center gap-3 py-2">
                  <div className="flex gap-1">
                    <div className="w-2 h-2 bg-orange-400 rounded-full animate-bounce"></div>
                    <div className="w-2 h-2 bg-orange-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
