            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Início</label>
            <input type="date" value={filterStartDate} onChange={(e) => setFilterStartDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Fim</label>
            <input type="date" value={filterEndDate} onChange={(e) => setFilterEndDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none" />
          </div>
        </div>
      )}

      {/* Main Table Container */}
      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Valor</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredTransactions.length > 0 ? filteredTransactions.map((t) => (
                <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6 text-sm font-bold text-slate-400">{new Date(t.date).toLocaleDateString('pt-MZ', { day: '2-digit', month: 'short' })}</td>
                  <td className="px-8 py-6">
                    <p className="text-sm font-black text-slate-900">{t.description}</p>
                  </td>
                  <td className="px-8 py-6">
                    <span className="inline-flex items-center gap-2 px-3 py-1.5 rounded-xl text-xs font-black bg-slate-100 text-slate-700">
                      {categories.find(c => c.id === t.categoryId)?.icon || '📁'} {categories.find(c => c.id === t.categoryId)?.name}
                    </span>
                  </td>
                  <td className="px-8 py-6">{getStatusBadge(t)}</td>
                  <td className={`px-8 py-6 text-base font-black text-right ${t.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>
                    {t.type === 'INCOME' ? '+' : '-'} {t.amount.toLocaleString('pt-MZ')} <span className="text-[10px] opacity-60">MZN</span>
                  </td>
                  <td className="px-8 py-6 text-center">
                    <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => startEditTransaction(t)} className="p-2 text-slate-400 hover:text-orange-500 transition-colors">
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"/></svg>
                      </button>
                      <button onClick={() => deleteTransaction(t.id)} className="p-2 text-slate-400 hover:text-rose-500 transition-colors">
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
                      </button>
                    </div>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={6} className="px-8 py-20 text-center text-slate-400 font-bold italic">Nenhum registro encontrado.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* SUMMARY BAR: Fixed at the bottom of the table area */}
        <div className="bg-slate-950 border-t border-slate-800 p-8 flex flex-col md:flex-row items-center justify-between gap-8">
          <div className="flex items-center gap-12 w-full md:w-auto">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Total Entradas</span>
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-2xl bg-orange-500/10 border border-orange-500/20 text-orange-500 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m18 15-6-6-6 6"/></svg>
                </div>
                <div className="flex flex-col">
                  <span className="text-xl font-black text-white">{totals.income.toLocaleString('pt-MZ')} <span className="text-xs text-slate-500">MZN</span></span>
                </div>
              </div>
            </div>

            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Total Saídas</span>
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-2xl bg-white/5 border border-white/10 text-white flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m6 9 6 6 6-6"/></svg>
                </div>
                <div className="flex flex-col">
                  <span className="text-xl font-black text-white">{totals.expense.toLocaleString('pt-MZ')} <span className="text-xs text-slate-500">MZN</span></span>
                </div>
              </div>
            </div>
          </div>

          <div className={`p-6 rounded-[32px] border-2 flex flex-col items-center md:items-end min-w-[240px] transition-all duration-500 shadow-2xl ${balance >= 0 ? 'bg-orange-500 border-orange-400 shadow-orange-500/20 text-white' : 'bg-white border-slate-200 text-slate-950 shadow-slate-200/50'}`}>
            <span className={`text-[10px] font-black uppercase tracking-[0.2em] mb-1 ${balance >= 0 ? 'text-white/80' : 'text-slate-400'}`}>Saldo do Período</span>
            <div className="flex items-baseline gap-2">
              <span className="text-3xl font-black">{balance.toLocaleString('pt-MZ')}</span>
              <span className="text-xs font-bold uppercase">MZN</span>
            </div>
          </div>
        </div>
      </div>

      {/* TRANSACTION MODAL */}
      {showTransactionModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm animate-fadeIn">
          <div className="bg-white rounded-[40px] w-full max-w-lg shadow-2xl overflow-hidden animate-scaleIn">
            <div className="px-8 py-6 bg-slate-50 border-b border-slate-200 flex items-center justify-between">
              <h3 className="text-xl font-black text-slate-900">{editingTransaction ? 'Editar Registro' : 'Novo Lançamento'}</h3>
              <button onClick={closeTransactionModal} className="p-2 hover:bg-slate-200 rounded-xl transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="text-slate-400"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              </button>
            </div>

            <div className="p-8 space-y-6">
              {/* Type Switcher */}
              <div className="grid grid-cols-2 gap-2 p-1 bg-slate-100 rounded-2xl border border-slate-200">
                <button 
                  onClick={() => setFormType('EXPENSE')} 
                  className={`py-3 rounded-xl text-xs font-black uppercase transition-all ${formType === 'EXPENSE' ? 'bg-rose-500 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Saída
                </button>
                <button 
                  onClick={() => setFormType('INCOME')} 
                  className={`py-3 rounded-xl text-xs font-black uppercase transition-all ${formType === 'INCOME' ? 'bg-emerald-500 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Entrada
                </button>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Descrição</label>
                  <input 
                    type="text" 
                    value={formDescription}
                    onChange={(e) => setFormDescription(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-bold"
                    placeholder="Ex: Venda de Café"
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Valor (MZN)</label>
                    <input 
                      type="number" 
                      value={formAmount}
                      onChange={(e) => setFormAmount(e.target.value)}
                      className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-black"
                      placeholder="0,00"
                    />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Data</label>
                    <input 
                      type="date" 
                      value={formDate}
                      onChange={(e) => setFormDate(e.target.value)}
                      className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-bold"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Categoria</label>
                  <select 
                    value={formCategoryId}
                    onChange={(e) => setFormCategoryId(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-bold appearance-none"
                  >
                    <option value="">Selecione uma categoria</option>
                    {categories.filter(c => c.type === formType).map(cat => (
                      <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Status</label>
                  <div className="grid grid-cols-3 gap-2">
                    {(['PENDING', 'COMPLETED', 'OVERDUE'] as TransactionStatus[]).map(s => (
                      <button 
                        key={s}
                        onClick={() => setFormStatus(s)}
                        className={`py-3 rounded-xl text-[10px] font-black uppercase transition-all border ${formStatus === s ? 'bg-slate-900 text-white border-slate-900 shadow-md' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`}
                      >
                        {s === 'PENDING' ? 'Pendente' : s === 'COMPLETED' ? 'Efetivado' : 'Atrasado'}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="pt-4 flex gap-3">
                <button 
                  onClick={closeTransactionModal}
                  className="flex-1 py-5 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-[24px] font-black text-xs uppercase tracking-widest transition-all"
                >
                  Cancelar
                </button>
                <button 
                  onClick={handleSaveTransaction}
                  className="flex-1 py-5 bg-orange-500 hover:bg-orange-600 text-white rounded-[24px] font-black text-xs uppercase tracking-widest transition-all shadow-xl shadow-orange-500/20 active:scale-[0.98]"
                >
                  Confirmar
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { AccountType, Transaction, Category, TransactionType, TransactionStatus } from '../types';

const STORAGE_KEY = 'fintech_transactions_v1';

export const TransactionsPage: React.FC<{ mode: AccountType }> = ({ mode }) => {
  const [showTransactionModal, setShowTransactionModal] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  // Search & Filter States
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [filterStatus, setFilterStatus] = useState<TransactionStatus | 'ALL'>('ALL');

  // Form States for New/Edit Transaction
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formDescription, setFormDescription] = useState('');
  const [formAmount, setFormAmount] = useState<string>('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [formType, setFormType] = useState<TransactionType>('EXPENSE');
  const [formStatus, setFormStatus] = useState<TransactionStatus>('COMPLETED');
  const [formCategoryId, setFormCategoryId] = useState('');

  // Initial State with Persistence Logic
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        console.error("Erro ao carregar dados do localStorage", e);
      }
    }
    // Default initial data if empty
    return [
      { id: '1', amount: 4500, description: 'Venda de Produto A', date: '2024-05-20', type: 'INCOME', status: 'COMPLETED', categoryId: '2', tenantId: 't1' },
      { id: '2', amount: 1200, description: 'Fornecedor de Embalagens', date: '2024-05-19', type: 'EXPENSE', status: 'PENDING', categoryId: '4', tenantId: 't1' },
      { id: '3', amount: 35000, description: 'Aluguel Escritório', date: '2024-05-15', type: 'EXPENSE', status: 'COMPLETED', categoryId: '3', tenantId: 't1' },
      { id: '4', amount: 15000, description: 'Consultoria Mensal', date: '2024-05-10', type: 'INCOME', status: 'OVERDUE', categoryId: '2', tenantId: 't1' },
    ];
  });

  // Effect to sync transactions to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(transactions));
  }, [transactions]);

  // State for Categories
  const [categories] = useState<Category[]>([
    { id: '1', name: 'Salário', icon: '💰', color: 'bg-emerald-500', type: 'INCOME' },
    { id: '2', name: 'Vendas', icon: '🛒', color: 'bg-emerald-500', type: 'INCOME' },
    { id: '3', name: 'Aluguel', icon: '🏠', color: 'bg-rose-500', type: 'EXPENSE' },
    { id: '4', name: 'Alimentação', icon: '🍔', color: 'bg-rose-500', type: 'EXPENSE' },
    { id: '5', name: 'Transporte', icon: '🚗', color: 'bg-rose-500', type: 'EXPENSE' },
  ]);

  // Derived filtered transactions
  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filterStatus === 'ALL' || t.status === filterStatus;
      const tDate = new Date(t.date).setHours(0,0,0,0);
      const matchesStart = !filterStartDate || tDate >= new Date(filterStartDate).setHours(0,0,0,0);
      const matchesEnd = !filterEndDate || tDate <= new Date(filterEndDate).setHours(0,0,0,0);
      return matchesSearch && matchesStatus && matchesStart && matchesEnd;
    });
  }, [transactions, searchTerm, filterStatus, filterStartDate, filterEndDate]);

  // Real-time calculation for the summary bar
  const totals = useMemo(() => {
    return filteredTransactions.reduce((acc, curr) => {
      if (curr.type === 'INCOME') {
        acc.income += curr.amount;
      } else {
        acc.expense += curr.amount;
      }
      return acc;
    }, { income: 0, expense: 0 });
  }, [filteredTransactions]);

  const balance = totals.income - totals.expense;

  const closeTransactionModal = () => {
    setShowTransactionModal(false);
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormDate(new Date().toISOString().split('T')[0]);
    setFormType('EXPENSE');
    setFormStatus('COMPLETED');
    setFormCategoryId('');
  };

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) {
      alert('Por favor, preencha todos os campos obrigatórios.');
      return;
    }

    const transactionData: Transaction = {
      id: editingTransaction?.id || Math.random().toString(36).substr(2, 9),
      amount: parseFloat(formAmount),
      description: formDescription,
      date: formDate,
      type: formType,
      status: formStatus,
      categoryId: formCategoryId,
      tenantId: 't1',
    };

    if (editingTransaction) {
      setTransactions(transactions.map(t => t.id === editingTransaction.id ? transactionData : t));
    } else {
      setTransactions([transactionData, ...transactions]);
    }

    closeTransactionModal();
  };

  const startEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setFormDescription(t.description);
    setFormAmount(t.amount.toString());
    setFormDate(t.date);
    setFormType(t.type);
    setFormStatus(t.status);
    setFormCategoryId(t.categoryId);
    setShowTransactionModal(true);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este lançamento?')) {
      setTransactions(transactions.filter(t => t.id !== id));
    }
  };

  const toggleTransactionStatus = (id: string) => {
    setTransactions(transactions.map(t => {
      if (t.id === id) {
        const nextStatus: TransactionStatus = t.status === 'COMPLETED' ? 'PENDING' : 'COMPLETED';
        return { ...t, status: nextStatus };
      }
      return t;
    }));
  };

  const getStatusBadge = (t: Transaction) => {
    const status = t.status;
    let colorClass = "";
    let label = "";

    switch (status) {
      case 'COMPLETED':
        colorClass = "bg-emerald-50 text-emerald-600 border-emerald-100";
        label = "Efetivado";
        break;
      case 'PENDING':
        colorClass = "bg-amber-50 text-amber-600 border-amber-100";
        label = "Pendente";
        break;
      case 'OVERDUE':
        colorClass = "bg-rose-50 text-rose-600 border-rose-100";
        label = "Atrasado";
        break;
    }

    return (
      <button 
        onClick={(e) => { e.stopPropagation(); toggleTransactionStatus(t.id); }}
        className={`px-3 py-1.5 rounded-full text-[10px] font-black border uppercase transition-all hover:shadow-md active:scale-95 ${colorClass}`}
      >
        {label}
      </button>
    );
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20">
      {/* Search and Action Bar */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div className="flex-1 max-w-2xl w-full">
          <div className="flex items-center gap-3">
            <div className="relative flex-1 group">
              <svg className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-orange-500 transition-colors" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
              <input 
                type="text" 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="Pesquisar registros..."
                className="w-full pl-12 pr-6 py-4 bg-white border border-slate-200 rounded-[24px] outline-none focus:ring-4 focus:ring-orange-500/10 focus:border-orange-500 transition-all font-medium text-slate-700 shadow-sm"
              />
            </div>
            <button 
              onClick={() => setShowFilters(!showFilters)}
              className={`p-4 rounded-[22px] transition-all flex items-center justify-center border shadow-sm ${showFilters ? 'bg-orange-500 border-orange-500 text-white shadow-orange-500/20' : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="21" x2="4" y1="4" y2="4"/><line x1="21" x2="4" y1="12" y2="12"/><line x1="21" x2="4" y1="20" y2="20"/><circle cx="7" cy="4" r="2"/><circle cx="17" cy="12" r="2"/><circle cx="7" cy="20" r="2"/></svg>
            </button>
          </div>
        </div>

        <div className="flex gap-3 w-full lg:w-auto">
          <button 
            onClick={() => setShowTransactionModal(true)} 
            className="flex-1 lg:flex-none bg-orange-500 hover:bg-orange-600 text-white px-8 py-4 rounded-[22px] font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 transition-all shadow-lg shadow-orange-500/20 active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
            Novo Lançamento
          </button>
        </div>
      </div>

      {/* Filter Panel */}
      {showFilters && (
        <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-xl grid grid-cols-1 md:grid-cols-3 gap-6 animate-slideDown">
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Status</label>
            <select 
              value={filterStatus} 
              onChange={(e) => setFilterStatus(e.target.value as any)}
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none"
            >
              <option value="ALL">Todos os Status</option>
              <option value="COMPLETED">Efetivado</option>
              <option value="PENDING">Pendente</option>
              <option value="OVERDUE">Atrasado</option>
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Início</label>
            <input type="date" value={filterStartDate} onChange={(e) => setFilterStartDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Fim</label>
            <input type="date" value={filterEndDate} onChange={(e) => setFilterEndDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none" />
          </div>
        </div>
      )}

      {/* Main Table Container */}
      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Valor</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredTransactions.length > 0 ? filteredTransactions.map((t) => (
                <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6 text-sm font-bold text-slate-400">{new Date(t.date).toLocaleDateString('pt-MZ', { day: '2-digit', month: 'short' })}</td>
                  <td className="px-8 py-6">
                    <p className="text-sm font-black text-slate-900">{t.description}</p>
                  </td>
                  <td className="px-8 py-6">
                    <span className="inline-flex items-center gap-2 px-3 py-1.5 rounded-xl text-xs font-black bg-slate-100 text-slate-700">
                      {categories.find(c => c.id === t.categoryId)?.icon || '📁'} {categories.find(c => c.id === t.categoryId)?.name}
                    </span>
                  </td>
                  <td className="px-8 py-6">{getStatusBadge(t)}</td>
                  <td className={`px-8 py-6 text-base font-black text-right ${t.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>
                    {t.type === 'INCOME' ? '+' : '-'} {t.amount.toLocaleString('pt-MZ')} <span className="text-[10px] opacity-60">MZN</span>
                  </td>
                  <td className="px-8 py-6 text-center">
                    <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => startEditTransaction(t)} className="p-2 text-slate-400 hover:text-orange-500 transition-colors">
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"/></svg>
                      </button>
                      <button onClick={() => deleteTransaction(t.id)} className="p-2 text-slate-400 hover:text-rose-500 transition-colors">
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
                      </button>
                    </div>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={6} className="px-8 py-20 text-center text-slate-400 font-bold italic">Nenhum registro encontrado.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* SUMMARY BAR: Fixed with persistence confirmation */}
        <div className="bg-slate-950 border-t border-slate-800 p-8 flex flex-col md:flex-row items-center justify-between gap-8">
          <div className="flex items-center gap-12 w-full md:w-auto">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Total Entradas</span>
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-2xl bg-orange-500/10 border border-orange-500/20 text-orange-500 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m18 15-6-6-6 6"/></svg>
                </div>
                <div className="flex flex-col">
                  <span className="text-xl font-black text-white">{totals.income.toLocaleString('pt-MZ')} <span className="text-xs text-slate-500">MZN</span></span>
                </div>
              </div>
            </div>

            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Total Saídas</span>
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-2xl bg-white/5 border border-white/10 text-white flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m6 9 6 6 6-6"/></svg>
                </div>
                <div className="flex flex-col">
                  <span className="text-xl font-black text-white">{totals.expense.toLocaleString('pt-MZ')} <span className="text-xs text-slate-500">MZN</span></span>
                </div>
              </div>
            </div>
          </div>

          <div className={`p-6 rounded-[32px] border-2 flex flex-col items-center md:items-end min-w-[240px] transition-all duration-500 shadow-2xl ${balance >= 0 ? 'bg-orange-500 border-orange-400 shadow-orange-500/20 text-white' : 'bg-white border-slate-200 text-slate-950 shadow-slate-200/50'}`}>
            <span className={`text-[10px] font-black uppercase tracking-[0.2em] mb-1 ${balance >= 0 ? 'text-white/80' : 'text-slate-400'}`}>Saldo do Período</span>
            <div className="flex items-baseline gap-2">
              <span className="text-3xl font-black">{balance.toLocaleString('pt-MZ')}</span>
              <span className="text-xs font-bold uppercase">MZN</span>
            </div>
          </div>
        </div>
      </div>

      {/* TRANSACTION MODAL */}
      {showTransactionModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm animate-fadeIn">
          <div className="bg-white rounded-[40px] w-full max-w-lg shadow-2xl overflow-hidden animate-scaleIn">
            <div className="px-8 py-6 bg-slate-50 border-b border-slate-200 flex items-center justify-between">
              <h3 className="text-xl font-black text-slate-900">{editingTransaction ? 'Editar Registro' : 'Novo Lançamento'}</h3>
              <button onClick={closeTransactionModal} className="p-2 hover:bg-slate-200 rounded-xl transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="text-slate-400"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              </button>
            </div>

            <div className="p-8 space-y-6">
              {/* Type Switcher */}
              <div className="grid grid-cols-2 gap-2 p-1 bg-slate-100 rounded-2xl border border-slate-200">
                <button 
                  onClick={() => setFormType('EXPENSE')} 
                  className={`py-3 rounded-xl text-xs font-black uppercase transition-all ${formType === 'EXPENSE' ? 'bg-rose-500 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Saída
                </button>
                <button 
                  onClick={() => setFormType('INCOME')} 
                  className={`py-3 rounded-xl text-xs font-black uppercase transition-all ${formType === 'INCOME' ? 'bg-emerald-500 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Entrada
                </button>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Descrição</label>
                  <input 
                    type="text" 
                    value={formDescription}
                    onChange={(e) => setFormDescription(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-bold"
                    placeholder="Ex: Venda de Café"
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Valor (MZN)</label>
                    <input 
                      type="number" 
                      value={formAmount}
                      onChange={(e) => setFormAmount(e.target.value)}
                      className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-black"
                      placeholder="0,00"
                    />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Data</label>
                    <input 
                      type="date" 
                      value={formDate}
                      onChange={(e) => setFormDate(e.target.value)}
                      className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-bold"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Categoria</label>
                  <select 
                    value={formCategoryId}
                    onChange={(e) => setFormCategoryId(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-bold appearance-none"
                  >
                    <option value="">Selecione uma categoria</option>
                    {categories.filter(c => c.type === formType).map(cat => (
                      <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Status</label>
                  <div className="grid grid-cols-3 gap-2">
                    {(['PENDING', 'COMPLETED', 'OVERDUE'] as TransactionStatus[]).map(s => (
                      <button 
                        key={s}
                        onClick={() => setFormStatus(s)}
                        className={`py-3 rounded-xl text-[10px] font-black uppercase transition-all border ${formStatus === s ? 'bg-slate-900 text-white border-slate-900 shadow-md' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`}
                      >
                        {s === 'PENDING' ? 'Pendente' : s === 'COMPLETED' ? 'Efetivado' : 'Atrasado'}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="pt-4 flex gap-3">
                <button 
                  onClick={closeTransactionModal}
                  className="flex-1 py-5 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-[24px] font-black text-xs uppercase tracking-widest transition-all"
                >
                  Cancelar
                </button>
                <button 
                  onClick={handleSaveTransaction}
                  className="flex-1 py-5 bg-orange-500 hover:bg-orange-600 text-white rounded-[24px] font-black text-xs uppercase tracking-widest transition-all shadow-xl shadow-orange-500/20 active:scale-[0.98]"
                >
                  Confirmar
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
